insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid, '{"es-MX":"Iniciador","it-IT":"Demolitore","ar-AE":"مبادر","es-ES":"Iniciador","en-US":"Initiator","de-DE":"Initiator","ja-JP":"イニシエーター","ko-KR":"척후대","fr-FR":"Initiateur","id-ID":"Initiator","pl-PL":"Inicjator","pt-BR":"Iniciador","th-TH":"Initiator","ru-RU":"Зачинщик","tr-TR":"Öncü","vi-VN":"Khởi tranh","zh-CN":"先锋","zh-TW":"先鋒"}'::jsonb, '{"es-MX":"Los iniciadores crean oportunidades para que el equipo pueda despejar ángulos, entrar a zonas en disputa y alejar a los defensores.","it-IT":"I Demolitori creano occasioni utili per permettere alla squadra di entrare in territori contesi e respingere i difensori.","ar-AE":"يواجه المبادرون الأركان بتسهيل دخول فرقهم إلى المناطق المتنازع عليها وطرد المدافعين منها.","es-ES":"Los iniciadores se centran en servirse de ángulos inusuales para ayudar a su equipo a adentrarse en territorios clave y alejar a los defensores.","en-US":"Initiators challenge angles by setting up their team to enter contested ground and push defenders away.","de-DE":"Initiatoren eröffnen neue Perspektiven und ermöglichen ihrem Team, umkämpftes Gelände zu betreten und die Verteidiger zu verdrängen.","ja-JP":"戦闘エリアで交戦するメンバーをサポートすることで様々な戦局に対処していく。","ko-KR":"척후대는 팀이 전투 지역에 침입할 수 있도록 다각도로 진입로를 확보하고 적 팀에 틈을 만들어냅니다.","fr-FR":"Les initiateurs sont là pour aider leur équipe à entrer dans des zones contestées et à repousser les défenseurs.","id-ID":"Initiator mengancam sudut dengan mengatur tim memasuki medan yang diperebutkan dan mendorong mundur defender.","pl-PL":"Inicjatorzy obserwują teren i przygotowują swoją drużynę, by ta mogła wejść do akcji i odepchnąć obrońców.","pt-BR":"Iniciadores desafiam situações arriscadas, preparando a equipe para entrar em terreno contestado e rechaçar defensores.","th-TH":"Initiator โดดเด่นในการช่วยเคลียร์พื้นที่เพื่อให้ทีมสามารถบุกเข้าไปในสนามรบและผลักดันฝ่ายป้องกันออกไป ","ru-RU":"Зачинщики отрабатывают опасные углы, проводя таким образом подготовку для захвата территории командой и оттесняя обороняющихся.","tr-TR":"Öncüler, ilerlemesi tehlikeli köşeleri aşabilmeleri için takımlarına olanaklar yaratır.","vi-VN":"Người Khởi tranh có nhiệm vụ tạo cơ hội cho đồng đội đẩy lùi hàng phòng ngự của đối thủ để đánh chiếm những vị trí quan trọng.","zh-CN":"先锋能够为队伍打开局面，帮助队友进入交战区域并驱逐敌方防守力量。","zh-TW":"先鋒能從不同角度切入且擊退守備方，替隊伍在詭譎多變的戰場中製造優勢。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/1b47567f-8f7b-444b-aae3-b0c634622d10/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('5fc02f99-4091-4486-a531-98459a3e95e9'::uuid, '{"es-MX":"Centinela","it-IT":"Guardiano","ar-AE":"حارس","es-ES":"Centinela","en-US":"Sentinel","de-DE":"Wächter","ja-JP":"センチネル","ko-KR":"감시자","fr-FR":"Sentinelle","id-ID":"Sentinel","pl-PL":"Strażnik","pt-BR":"Sentinela","th-TH":"Sentinel","ru-RU":"Страж","tr-TR":"Gözcü","vi-VN":"Hộ vệ","zh-CN":"哨卫","zh-TW":"守衛"}'::jsonb, '{"es-MX":"Los centinelas son expertos en defensa que aseguran áreas del mapa y vigilan los flancos, tanto en las rondas de defensa como de ataque.","it-IT":"I Guardiani sono esperti nella difesa e possono chiudere aree e coprire i fianchi, sia in attacco che in difesa.","ar-AE":"الحراس خبراء دفاعيون قادرون على تأمين المناطق ومراقبة الأجنحة في جولات الدفاع والهجوم على حد سواء.","es-ES":"Los centinelas son expertos en defensa que se centran en bloquear áreas y vigilar los flancos tanto durante las rondas de ataque como en las de defensa.","en-US":"Sentinels are defensive experts who can lock down areas and watch flanks, both on attacker and defender rounds.","de-DE":"Wächter sind Verteidigungsexperten, die sowohl in Angriffs- als auch in Verteidigungsrunden Bereiche absperren und Flanken bewachen können.","ja-JP":"あらゆる局面において、エリアの封鎖や側面における防衛に力を発揮する守りのエキスパート。","ko-KR":"감시자들은 공격팀이나 수비팀에 상관없이 지역을 점유하고 팀 엄호를 담당하는 수비 전문가입니다.","fr-FR":"Les sentinelles sont des experts de la défense qui verrouillent l''accès aux zones et surveillent les flancs, tant en attaque qu''en défense.","id-ID":"Sentinel adalah ahli pertahanan yang bisa mengunci area dan mengawasi sisi sayap, baik di ronde attacker dan defender.","pl-PL":"Strażnicy to eksperci od obrony, którzy potrafią zamknąć dany obszar i pilnować flank, zarówno w rundzie atakujących, jak i obrońców.","pt-BR":"Sentinelas são especialistas em defesa que podem bloquear áreas e vigiar flancos, tanto nas rodadas de ataque, quanto nas de defesa.","th-TH":"Sentinel คือผู้เชี่ยวชาญด้านการตั้งรับ โดยสามารถทำการปิดกั้นพื้นที่และคอยระวังหลังให้กับสมาชิกในทีม ทั้งในรอบการโจมตีและการตั้งรับ","ru-RU":"Стражи – эксперты по обороне, способные обеспечить прикрытие участков на поле боя и флангов как в защите, так и в нападении.","tr-TR":"Gözcüler hem saldıran hem savunan turlarında bölgeleri kapatabilen ve kanatları kolaçan eden savunma uzmanlarıdır.","vi-VN":"Hộ vệ là những chuyên gia phòng thủ, những người có thể cầm chân đối thủ trên diện rộng và canh gác bên sườn cho đồng đội cả trong vòng đấu tấn công cũng như phòng thủ.","zh-CN":"哨卫是防守的专家，为队伍封锁区域或盯防包夹，无论攻守回合均能发挥重要作用。","zh-TW":"守衛顧名思義就是守備專家。無論是攻擊或守備回合，都能夠為隊伍封鎖區域以及掩護側翼。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/5fc02f99-4091-4486-a531-98459a3e95e9/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid, '{"es-MX":"Duelista","it-IT":"Assassino","ar-AE":"مبارز","es-ES":"Duelista","en-US":"Duelist","de-DE":"Duellant","ja-JP":"デュエリスト","ko-KR":"타격대","fr-FR":"Duelliste","id-ID":"Duelist","pl-PL":"Szturmowiec","pt-BR":"Duelista","th-TH":"Duelist","ru-RU":"Дуэлянт","tr-TR":"Düellocu","vi-VN":"Đối đầu","zh-CN":"决斗","zh-TW":"決鬥者"}'::jsonb, '{"es-MX":"Los duelistas son asesinos autosuficientes con destrezas y habilidades que les permiten detonar los enfrentamientos y conseguir un gran número de asesinatos.","it-IT":"Gli Assassini sono combattenti autonomi. La loro squadra conta su di loro per uccidere gli avversari con abilità e tecniche, e ottenere un alto numero di uccisioni durante gli scontri.","ar-AE":"المبارزون هم قتلة يعتمدون على أنفسهم وتتوقع منهم فرقهم تنفيذ عمليات قتل كبرى والسعي إلى الالتحام دائمًا بفضل ما يتمتعون به من قدرات ومهارات.","es-ES":"Los duelistas son asesinos autosuficientes que, gracias a sus habilidades y destrezas, suelen conseguir iniciar enfrentamientos y anotarse muchos asesinatos.","en-US":"Duelists are self-sufficient fraggers who their team expects, through abilities and skills, to get high frags and seek out engagements first.","de-DE":"Duellanten sind unabhängige Fragger, die durch ihre Fähigkeiten und Fertigkeiten die ersten in ihrem Team sind, die auf Konfrontationskurs gehen und ordentlich austeilen.","ja-JP":"アビリティーやスキルを駆使しながら、敵と素早く交戦して次々とキルを重ねていく、頼れる自己完結型アタッカー。","ko-KR":"타격대는 자급자족이 가능하며 팀에서 공격을 담당합니다. 스킬과 실력을 통해 먼저 교전을 시작하고 적을 처치합니다.","fr-FR":"Les duellistes sont des combattants indépendants. Leur équipe compte sur eux pour tuer un maximum d''adversaires et provoquer des combats.","id-ID":"Duelist adalah pembunuh mandiri dengan kemampuan dan keahlian yang diandalkan oleh tim untuk menghasilkan angka pembunuhan tinggi dan melakukan serangan pertama.","pl-PL":"Szturmowcy to samowystarczalni zabójcy, którzy za sprawą swych umiejętności powinni zdobywać jak najwięcej zabójstw dla swojej drużyny i jako pierwsi nawiązywać kontakt ogniowy z wrogiem.","pt-BR":"Duelistas são abatedores independentes que estão sempre prontos para o confronto. Eles usam habilidades e perícia para conseguir vários abates.","th-TH":"Duelist คือหน่วยกล้าตายที่ไม่ต้องพึ่งพาใคร\nซึ่งเพื่อนร่วมทีมคาดหวังว่าด้วยสกิลและความสามารถ\nที่มีจะสามารถสร้างความเสียหายได้อย่างมาก \nและเข้าไปปะทะก่อนใครเพื่อน","ru-RU":"Дуэлянты – самодостаточные убийцы, от которых товарищи по команде ожидают высокой результативности и агрессивной игры. Добиться в этом успеха им позволяют их умения и навыки.","tr-TR":"Düellocular yetenek ve becerilerini kullanarak takımları için rakibe hasar yağdıran ve çatışma başlatan, kendi kendilerine yeten, etkili savaşçılardır.","vi-VN":"Đối đầu là vai trò của người chơi đủ khả năng tự lực cánh sinh, có kỹ năng để hạ gục nhiều đối thủ và luôn lao lên chiến đấu trước.","zh-CN":"决斗者是独当一面的战斗力，可利用其技能为队伍输出伤害，并主动寻找与对手交战的机会。","zh-TW":"決鬥者是獨當一面的殺手，隊伍皆仰賴其高超技巧，尋找開戰的契機、殲滅敵方。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/dbe8757e-9e92-4ed4-b39f-9dfc589691d4/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid, '{"es-MX":"Controlador","it-IT":"Stratega","ar-AE":"متحكم","es-ES":"Controlador","en-US":"Controller","de-DE":"Taktiker","ja-JP":"コントローラー","ko-KR":"전략가","fr-FR":"Contrôleur","id-ID":"Controller","pl-PL":"Kontroler","pt-BR":"Controlador","th-TH":"Controller","ru-RU":"Специалист","tr-TR":"Kontrol Uzmanı","vi-VN":"Kiểm soát","zh-CN":"控场","zh-TW":"控場者"}'::jsonb, '{"es-MX":"Los controladores son expertos en dividir y preparar el terreno para darle una ventaja a su equipo","it-IT":"Gli Strateghi sono esperti nella preparazione dei territori pericolosi per consentire alla loro squadra di vincere le battaglie.","ar-AE":"المتحكمون يجيدون تقسيم المناطق الخطرة لتوزيع فرقهم بشكل يضمن تحقيق النجاح.","es-ES":"Los controladores se especializan en dividir terrenos peligrosos en varias zonas para que su equipo pueda encargarse del resto.","en-US":"Controllers are experts in slicing up dangerous territory to set their team up for success.","de-DE":"Taktiker analysieren das Schlachtfeld und finden so für ihr Team den besten Weg zum Ziel.","ja-JP":"危険なエリアを特定し、チームを勝利に導く戦略のエキスパート。","ko-KR":"전략가들은 위험 지역을 분석하여 팀을 승리로 이끄는 데 탁월합니다.","fr-FR":"Les contrôleurs excellent à diviser les zones dangereuses pour permettre à leur équipe de remporter la victoire.","id-ID":"Controller adalah ahli pembagian wilayah berbahaya untuk mempersiapkan keberhasilan tim.","pl-PL":"Kontrolerzy to eksperci w rozpracowywaniu niebezpiecznych obszarów, dzięki czemu mogą przygotować swoją drużynę do zwycięstwa.","pt-BR":"Controladores se dedicam a dissecar territórios perigosos e pavimentar o caminho do sucesso para a equipe.","th-TH":"Controller เชี่ยวชาญในการจัดการกับพื้นที่อันตราย เพื่อนำทีมของพวกเขาไปสู่ความสำเร็จ","ru-RU":"Специалисты по контролю мастерски справляются с угрозами на местности, чтобы обеспечить команде победу.","tr-TR":"Kontrol uzmanları takımlarını başarıya götürmek için tehlikeli bölgeleri ayrıştırmakta uzmandır.","vi-VN":"Người Kiểm soát là bậc thầy trong việc phân tích những địa thế nguy hiểm và tìm con đường tới chiến thắng cho đội mình.","zh-CN":"控场者是改变和利用战场地形的专家，为队伍的胜利创造有利条件。","zh-TW":"控場者擅長分割地帶，阻隔危險，替隊伍作好迎接勝利的準備。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/4ee40330-ecdd-4f2f-98a8-eb1243428373/displayicon.png') on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, '{"es-MX":"Gekko","it-IT":"Gekko","ar-AE":"غيكو","es-ES":"Gekko","en-US":"Gekko","de-DE":"Gekko","ja-JP":"ゲッコー","ko-KR":"게코","fr-FR":"Gekko","id-ID":"Gekko","pl-PL":"Gekko","pt-BR":"Gekko","th-TH":"Gekko","ru-RU":"Gekko","tr-TR":"GEKKO","vi-VN":"Gekko","zh-CN":"盖可","zh-TW":"蓋克"}'::jsonb, '{"es-MX":"Gekko, el nativo de Los Ángeles, lidera un grupo de criaturas revoltosas, y son como uña y mugre. Sus amiguitos avanzan a toda velocidad, dispersando a los enemigos, y Gekko los persigue para reagruparlos y lanzarlos de nuevo.","it-IT":"Gekko, originario di Los Angeles, guida un''affiatata cricca di turbolente creature. I suoi amichetti irrompono in territorio ostile, disperdendo i nemici sulla loro strada, con Gekko alle loro calcagna, pronto a recuperarli e ripartire da capo.","ar-AE":"جاء غيكو من لوس أنجلوس، وهو يتزعم عصبة من المخلوقات الفوضوية التي تجمع بينها روابط وثيقة. وينطلق رفاقه إلى الأمام لتفريق الأعداء وفتح الطريق، ويمضي غيكو خلفهم لجمعهم وإعادة الكرّة.","es-ES":"Gekko, de Los Ángeles, lidera una pequeña pandilla de calamitosas criaturas. Sus colegas toman la delantera para dispersar a los enemigos, mientras que Gekko los persigue para luego reagruparse y repetir el proceso.","en-US":"Gekko the Angeleno leads a tight-knit crew of calamitous creatures. His buddies bound forward, scattering enemies out of the way, with Gekko chasing them down to regroup and go again.","de-DE":"Gekko der Angeleno führt eine eingeschworene Truppe verrückter Kreaturen. Seine Freunde springen voran und vertreiben Gegner, während Gekko ihnen folgt, um sie einzusammeln und von vorne anzufangen.","ja-JP":"ロサンゼルス出身のゲッコーは、固い絆で結ばれた暴れん坊のクリーチャーたちを率いている。敵を蹴散らしながら進むクリーチャーをゲッコーが追い、集め、力を合わせて戦い続ける。","ko-KR":"로스앤젤레스 출신 게코는 무시무시한 봇 생명체들을 이끕니다. 봇들이 돌진해 적들을 분산시키면 게코가 따라가 전열을 재정비한 후 다시 공격을 개시합니다.","fr-FR":"Originaire de Los Angeles, Gekko dirige une bande de créatures chaotiques, mais très soudées. Ses amis s''occupent de disperser les ennemis, puis Gekko rassemble sa petite troupe pour recommencer.","id-ID":"Gekko the Angeleno memimpin pasukan kompak yang terdiri dari makhluk-mahkluk berbahaya. Usai pasukannya bergerak maju dan menyingkirkan musuh, Gekko mengejar dan mengambil mereka kembali lalu beranjak lagi.","pl-PL":"Gekko Angeleno przewodzi zgranej ekipie groźnych stworzeń. Jego kumple szarżują przed siebie, odrzucając wrogów z drogi, a Gekko ściga ich, by przegrupowali się i ponownie ruszyli do akcji.","pt-BR":"Gekko, de Los Angeles, lidera um grupo muito unido de criaturas caóticas. Seus amigos atropelam tudo, tirando os inimigos do caminho. Depois, Gekko corre atrás deles para reagrupá-los e reiniciar o processo.","th-TH":"Gekko เอเจนท์จากลอสแอนเจลิสจะนำพากลุ่มสิ่งมีชีวิตอภิมหาตัวป่วนมารวมตัวกัน เหล่าสหายของเขาจะพุ่งไปด้านหน้า ขับไล่ศัตรูออกไปให้พ้นทาง พร้อมกับ Gekko ที่จะคอยตามเก็บพวกมันเพื่อมารวมกลุ่มกันและจัดการลุยกันอีกครั้ง","ru-RU":"Gekko из Лос-Анджелеса заправляет дружной командой безбашенных существ. Его верные зверята смело бросаются в драку, разнося врагов в пух и прах. А когда Gekko подбирает питомцев с поля боя, можно перевести дух и повторить!","tr-TR":"Los Angeles çocuğu Gekko yaratıklardan oluşan belalı tayfasına liderlik etmekte. Gekko''nun tayfası ileri atılarak düşmanların başına bela olur. Sonrasında Gekko onları toplar ve birlikte tekrar bela olacak düşman aramaya koyulurlar.","vi-VN":"Gekko - gã trai phố thị L.A. - là người dẫn đầu biệt đội toàn những sinh vật \"lắm chiêu\" và rất thân thiết. Gekko đuổi theo những đồng đội đang mải miết lao tới hất tung tất cả kẻ thù đang ngáng đường, ráng sức tập hợp chúng lại để có thể tiếp tục ra chiêu.","zh-CN":"西海岸小伙“盖可”随身带着一群调皮捣蛋的小怪兽。这些小跟班们负责冲在战斗的最前方，给敌人制造各种麻烦。等到盖可追上来后，它们还能回到他身边，然后再次出击。","zh-TW":"洛杉磯人蓋克帶領了一群親密無間的小怪物。他的好夥伴總是一馬當先，打亂敵人陣腳，等蓋克追上後再重整隊伍，再次出擊。"}'::jsonb, 'Aggrobot', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/displayicon.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/displayicon.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/killfeedportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/minimapportrait.png', null, 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/background.png', array['371c5cff', '0f1923ff', '3a2656ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, '{"es-MX":"Fade","it-IT":"Fade","ar-AE":"فايد","es-ES":"Fade","en-US":"Fade","de-DE":"Fade","ja-JP":"フェイド","ko-KR":"페이드","fr-FR":"Fade","id-ID":"Fade","pl-PL":"Fade","pt-BR":"Fade","th-TH":"Fade","ru-RU":"Fade","tr-TR":"FADE","vi-VN":"Fade","zh-CN":"黑梦","zh-TW":"菲德"}'::jsonb, '{"es-MX":"Fade, la cazarrecompensas turca, desata el poder de las pesadillas para apoderarse de los secretos del enemigo. En armonía con el terror puro, acecha a sus objetivos y revela sus miedos más profundos, antes de aplastarlos en la oscuridad.","it-IT":"Fade, la cacciatrice di taglie turca, scatena il potere degli incubi per impossessarsi dei segreti nemici. In sintonia con il terrore, dà la caccia ai bersagli e rivela le loro paure più recondite, per poi trascinarli via nel buio.","ar-AE":"تطلق فايد، صيادة الجوائز التركية، عنان قوة الكابوس الخالصة لانتزاع أسرار الأعداء. وبفضل انسجامها مع الرعب ذاته، تطارد الأهداف وتكشف عن أسوأ مخاوفهم، قبل سحقهم في الظلام.","es-ES":"Fade, la cazarrecompensas turca, controla el poder de las pesadillas para poner al descubierto los secretos de los enemigos. Ataviada con el propio terror, da caza a sus objetivos y revela sus miedos más profundos, para después acabar con ellos en la oscuridad.","en-US":"Turkish bounty hunter Fade unleashes the power of raw nightmare to seize enemy secrets. Attuned with terror itself, she hunts down targets and reveals their deepest fears - before crushing them in the dark.","de-DE":"Die türkische Kopfgeldjägerin Fade entlockt Gegnern mit der Macht der Albträume ihre Geheimnisse. Sie arbeitet mit dem Schrecken selbst zusammen, jagt ihre Ziele und enthüllt deren Ängste – bevor sie sie in der Dunkelheit zermalmt.","ja-JP":"トルコ出身の賞金稼ぎのフェイドは、むき出しの悪夢の力を解き放ち、敵の秘密を掴む。恐怖そのものと同調している彼女は、追い詰めたターゲットの心の奥底にある恐怖を掘り起こし、そして闇に葬る。","ko-KR":"튀르키예 출신 현상금 사냥꾼 페이드는 악몽의 힘을 이용해 적의 비밀을 캐냅니다. 공포와 하나가 되어 표적을 쫓고 마음속 가장 깊은 곳에 숨겨진 공포를 파헤친 뒤, 어둠 속에서 짓밟습니다.","fr-FR":"Originaire de Türkiye, la chasseuse de primes Fade utilise le pouvoir des cauchemars pour s''emparer des secrets ennemis. Elle traque ses cibles et révèle leurs plus grandes peurs pour mieux les briser dans l''obscurité.","id-ID":"Pemburu bayaran asal Turki, Fade, menggunakan mimpi buruk yang nyata sebagai kekuatannya untuk merebut rahasia musuh. Dia memburu target dan menyingkap ketakutan terdalam dari musuhnya-sebelum mereka dihancurkan di dalam kegelapan.","pl-PL":"Turecka łowczyni nagród Fade czerpie z czystej mocy koszmarów, aby odkryć tajemnice wroga. Dzięki swojemu zestrojeniu z przerażeniem dopada swoje cele i ujawnia najgłębiej skrywane przez nich lęki, zanim zmiażdży ich w mroku.","pt-BR":"Fade, uma caçadora de recompensas turca, usa o poder dos pesadelos para capturar os segredos dos inimigos. Personificando o próprio terror, ela persegue os alvos e revela seus medos mais profundos para, depois, destruí-los na escuridão.","th-TH":"Fade นักล่าค่าหัวชาวตุรกีจะมาปลดปล่อยพลังแห่งฝันร้ายอันทรงพลังเพื่อช่วงชิงความลับของศัตรู เอเจนท์ที่หลอมรวมเข้ากับความหวาดกลัวผู้นี้จะไล่ล่าเป้าหมายของเธอและดึงเอาความกลัวที่ฝังลึกในใจของพวกเขาออกมา ก่อนที่จะจัดการพวกเขาภายใต้เงามืด","ru-RU":"Турчанка Fade, охотница за головами, связала свою жизнь с Кошмаром и научилась читать врагов как открытые книги с помощью силы этого существа. Впустив в свое сердце кромешную тьму, она получила способность раскрывать чужие страхи и сводить жертву с ума.","tr-TR":"Türk kelle avcısı Fade, düşmanların sırlarını gasp etmek için saf kâbus gücünü kullanır. Korkuyla uyum içinde çalışarak hedeflerini avlar ve hedeflerinin işini bitirmeden önce en büyük korkularını açığa çıkarır.","vi-VN":"Fade - thợ săn tiền thường tới từ Thổ Nhĩ Kỳ, người điều khiển sức mạnh ác mộng để chiếm đoạt những bí mật của kẻ thù. Là hiện thân của sự sợ hãi, cô ấy săn đuổi và khai thác những nỗi sợ sâu thẳm nhất của mục tiêu - trước khi nghiền nát chúng trong bóng tối.","zh-CN":"“黑梦”是来自小亚细亚地区的赏金猎人，她能够操纵纯粹的噩梦能量，揭开他人心底潜藏的恐惧和秘密。她会如梦魇般对敌人穷追不舍，然后在黑暗中将其摧毁殆尽。","zh-TW":"來自土耳其的賞金獵人菲德能釋放純粹的惡夢能量來攫取敵人的祕密。她是恐懼的化身，能追獵目標，揭開他們最深層的恐懼，然後用黑暗將其摧毀殆盡。"}'::jsonb, 'BountyHunter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/displayicon.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/displayicon.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/killfeedportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/minimapportrait.png', null, 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/background.png', array['1d2846ff', '0f1923ff', '18344cff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, '{"es-MX":"Breach","it-IT":"Breach","ar-AE":"بريتش","es-ES":"Breach","en-US":"Breach","de-DE":"Breach","ja-JP":"ブリーチ","ko-KR":"브리치","fr-FR":"Breach","id-ID":"Breach","pl-PL":"Breach","pt-BR":"Breach","th-TH":"Breach","ru-RU":"Breach","tr-TR":"BREACH","vi-VN":"Breach","zh-CN":"铁臂","zh-TW":"叛奇"}'::jsonb, '{"es-MX":"El sueco biónico Breach lanza poderosas ráfagas cinéticas para abrirse paso a la fuerza a través del territorio enemigo. El daño y la disrupción que inflige garantizan que ninguna pelea sea justa.","it-IT":"Breach, lo svedese bionico, spara potenti scariche cinetiche mirate ad aprire un varco in modo aggressivo in territorio nemico. I danni e la distruzione che infligge conferiscono un enorme vantaggio in ogni scontro.","ar-AE":"يطلق بريتش، الرجل نصف الآلي القادم من السويد، دفقات من الطاقة الحركية القوية والموجهة لكي يخلي الطريق بكل شراسة في منطقة الأعداء. كم الضرر والتشويش الذي يسببه يضمن ألا يكون القتال عادلًا أبدًا.","es-ES":"Breach, el sueco biónico, dispara una serie de explosiones cinéticas controladas para abrirse paso por el territorio enemigo. Su capacidad para infligir daño y sembrar el caos garantiza que los combates siempre estén de su parte.","en-US":"The bionic Swede Breach fires powerful, targeted kinetic blasts to aggressively clear a path through enemy ground. The damage and disruption he inflicts ensures no fight is ever fair.","de-DE":"Der bionisch augmentierte Schwede Breach verursacht gezielt mächtige, kinetische Explosionen, die ohne Rücksicht auf Verluste den Weg frei räumen. Der Schaden und die Massenkontrolle stellen sicher, dass kein Kampf je fair ist.","ja-JP":"生体工学を駆使した義肢を操るスウェーデン人のブリーチは、強力な衝撃波を放つことで、敵陣地への突破口を切り開く。敵にダメージや撹乱を与えることで、戦いを有利に進めることが可能だ。","ko-KR":"스웨덴 출신의 생체병기 브리치는 강력한 역학적 폭발을 이용해 적진을 돌파합니다. 브리치의 강력한 피해량과 교란술은 아군이 굳이 ''공정한'' 전투를 할 필요가 없게 만들죠.","fr-FR":"Breach, le Suédois bionique, tire de puissantes décharges cinétiques pour ouvrir un chemin en territoire ennemi. Grâce aux dégâts et aux diversions ainsi provoqués, jamais un combat n''est en sa défaveur.","id-ID":"Breach, bionik dari Swedia ini menembakkan ledakan kuat untuk mengosongkan jalan menembus wilayah musuh. Damage dan gangguan yang dia timbulkan memastikan pertarungan tidak pernah adil.","pl-PL":"Breach, bioniczny reprezentant Szwecji, wystrzeliwuje potężne namierzane wybuchy kinetyczne, które pozwalają przebić się przez szeregi wroga. Zadawane przez niego obrażenia i zakłócenie sprawiają, że żadna walka nie jest wyrównana.","pt-BR":"Breach, o homem-biônico sueco, dispara poderosos jatos cinéticos para forçar a abertura de um caminho pelo território inimigo. O dano e a interrupção que ele causa garantem que nenhuma luta seja justa.","th-TH":"Breach ไบโอนิคชาวสวีเดนสามารถยิงพลังระเบิดอันรุนแรง เป้าหมายของเขาคือการเคลียร์เส้นทางในสนามรบของศัตรู ทุกความเสียหายและการก่อกวนที่เขาสร้างนั้นรุนแรง จนมั่นใจได้เลยว่าเกมจะไม่ยุติธรรมกับคู่แข่งแน่นอน","ru-RU":"Использующий бионические усиления швед Breach полагается на мощные направленные взрывы, чтобы расчистить путь от агентов противника. Разрушительная сила его умений позволяет получить решающее преимущество в любом бою.","tr-TR":"İnsanüstü güçlere sahip İsveçli Breach, düşman zemininde sert bir şekilde yolu açan, hedeflenebilir kinetik dalgalar gönderir. Sebep olduğu hasar ve darbeler, savaşın dengelerini değiştirecek niteliktedir.","vi-VN":"Breach, gã Thụy Điển với thân hình đầy máy móc, có thể bắn ra các luồng năng lượng động học mạnh mẽ tới mục tiêu và mở đường xuyên qua lãnh địa của đối phương. Với sát thương đáng kể cùng khả năng gây rối, Breach luôn đảm bảo đồng đội chiếm được thế thượng phong khi giao chiến.","zh-CN":"生化改造人“铁臂”来自北欧波罗的海西岸，他能够使用定向爆破和动能冲击从敌阵中强行打开一条通道。他从来不跟敌人讲道理，火力和爆破就是硬道理。","zh-TW":"瑞典生化人叛奇，能發射強大且精準的雷射震擊，通過火力壓制開闢前往敵區的道路。能夠阻斷敵方，又能造成傷害的他，絕對是確保敵我雙方實力懸殊的不二人選。"}'::jsonb, 'Breach', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/displayicon.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/displayicon.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/killfeedportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/minimapportrait.png', null, 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/background.png', array['81331aff', '0f1923ff', '523a23ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, '{"es-MX":"Deadlock","it-IT":"Deadlock","ar-AE":"ديدلوك","es-ES":"Deadlock","en-US":"Deadlock","de-DE":"Deadlock","ja-JP":"デッドロック","ko-KR":"데드록","fr-FR":"Deadlock","id-ID":"Deadlock","pl-PL":"Deadlock","pt-BR":"Deadlock","th-TH":"Deadlock","ru-RU":"Deadlock","tr-TR":"DEADLOCK","vi-VN":"Deadlock","zh-CN":"钢锁","zh-TW":"蒂羅"}'::jsonb, '{"es-MX":"La agente noruega Deadlock despliega una variedad de nanocables de alta tecnología para asegurar el campo de batalla, incluso en los asaltos más letales. Nadie escapa de su ojo vigilante ni sobrevive a su ferocidad inquebrantable.","it-IT":"L''agente norvegese Deadlock si serve di una rivoluzionaria varietà di nanofilo per difendere il campo di battaglia dagli assalti più letali. Nessuno può eludere la sua vigile sorveglianza, né sopravvivere alla sua irriducibile ferocia.","ar-AE":"تنشر العميلة النرويجية ديدلوك مجموعة من أسلاك النانو المتطورة لتأمين ميدان المعركة حتى من أكثر الهجمات فتكًا. ولا أحد يفلت من مراقبتها اليقظة، ولا ينجو أحد من ضراوتها التي لا تلين.","es-ES":"Deadlock, la agente noruega, despliega un surtido de avanzados nanocables para defender el campo de batalla de cualquier asalto, por letal que sea. Nadie escapa a su atenta mirada ni sobrevive a su implacable ferocidad.","en-US":"Norwegian operative Deadlock deploys an array of cutting-edge nanowire to secure the battlefield from even the most lethal assault. No one escapes her vigilant watch, nor survives her unyielding ferocity.","de-DE":"Die norwegische Elitesoldatin Deadlock bedient sich verschiedener High-Tech-Nanodrahtgeräte, um das Schlachtfeld vor den tödlichsten Angriffen zu schützen. Nichts und niemand entgeht ihren Argusaugen und ihre Entschlossenheit hat noch jeden Gegner zur Strecke gebracht.","ja-JP":"ノルウェー出身の工作員、デッドロックは最先端のナノワイヤー技術を駆使し、危険な襲撃の最中においても戦場の要所を確保する。その油断のない監視、そして不屈の獰猛さから逃れられる者はいない。","ko-KR":"노르웨이 출신 요원 데드록은 최첨단 나노와이어를 배치해 전장의 위협적인 공격을 막아냅니다. 누구도 데드록의 감시를 피할 수도, 집요한 공격에서 살아남을 수도 없습니다.","fr-FR":"Deadlock, l''agent spécial norvégien, déploie un éventail de nanocâbles ultra-modernes pour défendre sa position contre le plus violent des assauts. Nul n''échappe à sa vigilance ni ne survit à sa cruelle ténacité.","id-ID":"Detektif Norwegia, Deadlock, mengerahkan nanowire mutakhir untuk mengamankan battlefield dari serangan yang paling mematikan sekalipun. Tidak ada yang bisa lolos dari pengawasan ketatnya, ataupun bertahan dari kebengisannya.","pl-PL":"Norweska agentka Deadlock korzysta z nowatorskich nanoobwodów, aby zabezpieczyć pole walki przed nawet najbardziej zabójczym atakiem. Nic jej nie umknie i nikt nie przetrwa jej bezwzględnej zaciekłości.","pt-BR":"A agente norueguesa Deadlock posiciona uma gama de nanofios de alta tecnologia para proteger o campo de batalha até mesmo do ataque mais letal. Ninguém escapa do seu olhar vigilante. Ninguém sobrevive à sua ferocidade implacável.","th-TH":"Deadlock สายลับชาวนอร์เวย์ ผู้เชี่ยวชาญการใช้เส้นลวดนาโนล้ำยุคเพื่อควบคุมสถานการณ์ในสนามรบ และพร้อมรับมือแม้กระทั่งการบุกโจมตีที่หนักหน่วงที่สุด ไม่มีใครเล็ดลอดไปจากสายตาที่จับจ้องของเธอได้ และไม่เคยมีผู้ใดรอดชีวิตจากความดุร้ายไร้ปราณีของเธอ","ru-RU":"Уроженка Норвегии Deadlock известна своим упорством и суровостью. Она контролирует ситуацию на поле боя с помощью наноустройств, и никто не может ускользнуть от ее зоркого взгляда.","tr-TR":"Norveçli ajan Deadlock, savaş esnasında en ölümcül saldırıları bile savuşturabilecek son teknoloji bir nanobağ ağı kullanır. Keskin gözlerinden kaçan, vahşetinden kurtulan olmamıştır.","vi-VN":"Đặc Vụ người Na-uy: Deadlock, sử dụng hàng loạt sợi dây nano tân tiến nhằm bảo vệ chiến trường khỏi những đợt công kích nguy hiểm nhất. Chẳng ai có thể thoát khỏi sự truy sát gắt gao, cũng như không thể sống sót trước sự hung dữ ngoan cường của cô ấy.","zh-CN":"来自北欧的特工“钢锁”配备着多种尖端纳米纤维武器，她擅长监听战场动态和阻碍对手移动。一旦敌人遭到锁定，将面对她凌厉无情的攻势并难逃一劫。","zh-TW":"挪威籍特務蒂羅佈下大量尖端科技奈米線守住陣地，就連最致命的攻擊也難越雷池一步。在她的警戒下，誰都逃不過她的法眼。她對敵人從不手下留情，遇上她絕對九死而無一生。"}'::jsonb, 'Cable', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/displayicon.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/displayicon.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/killfeedportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/minimapportrait.png', null, 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/background.png', array['425495ff', '0f1923ff', '221c3dff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, '{"es-MX":"Tejo","it-IT":"Tejo","ar-AE":"تيهو","es-ES":"Tejo","en-US":"Tejo","de-DE":"Tejo","ja-JP":"テホ","ko-KR":"테호","fr-FR":"Tejo","id-ID":"Tejo","pl-PL":"Tejo","pt-BR":"Tejo","th-TH":"Tejo","ru-RU":"Tejo","tr-TR":"TEJO","vi-VN":"Tejo","zh-CN":"钛狐","zh-TW":"戴侯"}'::jsonb, '{"es-MX":"Tejo es un consultor de inteligencia veterano proveniente de Colombia. Su sistema de guía balística presiona al enemigo para que renuncie a su territorio... o a su vida. Sus ataques dirigidos mantienen a sus oponentes fuera de balance y bajo control.","it-IT":"Esperto consulente di intelligence proveniente dalla Colombia, Tejo sfrutta un sistema missilistico guidato per costringere i nemici a cedere terreno... o a cedere le proprie vite. I suoi bombardamenti mirati non danno tregua agli avversari e gli permettono di tenerli in pugno.","ar-AE":"تيهو مستشار استخبارات مخضرم من كولومبيا، يستخدم نظام التوجيه الباليستي للضغط على العدو كي يتخلى عن مواقعه، وإلا فالموت مصيره. كما تبقي ضرباته الموجهة الخصومَ في حالة من عدم التوازن وتحت سيطرته.","es-ES":"Tejo, un consultor de inteligencia veterano de Colombia, controla un sistema de guiado balístico que obliga a sus enemigos a decidir entre renunciar a su posición... o a sus vidas. Sus ataques dirigidos pondrán en jaque a sus contrincantes y los dejará a su merced.","en-US":"A veteran intelligence consultant from Colombia, Tejo’s ballistic guidance system pressures the enemy to relinquish their ground - or their lives. His targeted strikes keep opponents off balance and under his heel.","de-DE":"Tejo ist ein kolumbianischer Aufklärungsveteran und besitzt ein ballistisches Leitsystem, mit dem er Gegner dazu zwingt, ihre Stellung aufzugeben … oder sie mit ihrem Leben zu verteidigen. Seine zielgenauen Angriffe bringen Gegner ständig aus dem Konzept und lassen sie nicht zur Ruhe kommen.","ja-JP":"テホはコロンビア出身の退役軍人であり、諜報コンサルタントだ。彼の弾道誘導システムは敵に陣地を明け渡すか、または命を差し出すかの選択を迫る。その精密な攻撃は敵を揺るがし、彼の狙いのもとに押さえ込む。","ko-KR":"콜롬비아 출신의 베테랑 정보 자문가인 테호는 탄도 유도 시스템을 이용해 적이 위치나 목숨을 포기하도록 압박합니다. 테호의 표적 공격은 상대의 균형을 무너뜨리고 완전히 통제합니다.","fr-FR":"Originaire de Colombie, Tejo est un conseiller vétéran dans le domaine du renseignement. Son système de guidage balistique force les ennemis à perdre du terrain, voire la vie. Ses frappes chirurgicales lui permettent de garder les ennemis sous son emprise.","id-ID":"Seorang konsultan intelijen veteran dari Kolombia, Tejo, bersama sistem pemandu balistiknya menekan musuh untuk menyerahkan wilayah mereka—atau nyawa mereka. Serangannya yang terarah terus membuat lawannya kocar-kacir dan berada di bawah kendalinya.","pl-PL":"Tejo, doświadczony konsultant wywiadowczy z Kolumbii, za pomocą swojego balistycznego systemu naprowadzania wymusza na wrogu wycofanie się z zajmowanego terenu, jeśli ten ceni sobie swoje życie. Jego namierzane ataki zaburzają szyk przeciwnika, zapewniając mu przewagę.","pt-BR":"Consultor de inteligência veterano da Colômbia, Tejo conta com um sistema de orientação balística que força o inimigo a abrir mão da posição — ou da própria vida. Os ataques precisos dele mantêm os oponentes desestabilizados e sob seu controle.","th-TH":"Tejo ที่ปรึกษาข่าวกรองมากประสบการณ์จากโคลอมเบีย จะใช้ระบบนำทางขีปนาวุธกดดันให้ศัตรูต้องเลือกว่าจะทิ้งพื้นที่หรือชีวิตของตัวเอง การโจมตีแบบเจาะจงเป้าหมายของเขาจะทำให้คู่ต่อสู้ปั่นป่วนและไม่อาจขัดขืน","ru-RU":"Tejo – бывалый разведчик-эксперт из Колумбии. Используемая им система наведения огня вынуждает врагов сдавать позиции – или прощаться с жизнью. Его прицельные ракетные удары застигают противника врасплох и заставляют пластаться по земле.","tr-TR":"Kolombiyalı deneyimli istihbarat danışmanı Tejo''nun balistik güdüm sistemi düşmanları oldukları yerden çıkmaya veya canlarını vermeye zorlar. İsabetli saldırıları sayesinde Tejo rakiplerinin dengesini bozar ve onlara karşı üstünlük kurar.","vi-VN":"Một nhà tư vấn tình báo kỳ cựu từ Colombia, hệ thống đạn đạo tự tìm đường của Tejo gây áp lực buộc kẻ thù phải từ bỏ vị trí, hoặc mạng sống của chúng. Các đợt công kích nhắm mục tiêu của hắn khiến đối thủ mất cân bằng và bị kiểm soát hoàn toàn.","zh-CN":"“钛狐”是来自南美洲的资深情报顾问。他的弹道制导系统可以向敌人施压，迫使其做出选择——要么放弃阵地，要么放弃生命。受到精准打击后，对手往往会失去平衡，被他轻易击败。","zh-TW":"「戴侯」是來自哥倫比亞的資深情報顧問，他的彈道導引系統能迫使敵人放棄陣地……甚或賠上性命。他的精確打擊能讓對手陷入混亂，臣服於他的掌控之下。"}'::jsonb, 'Cashew', '2025-01-08T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/displayicon.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/displayicon.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/killfeedportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/minimapportrait.png', null, 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/background.png', array['80451bff', '0f1923ff', 'ffffffff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, '{"es-MX":"Raze","it-IT":"Raze","ar-AE":"رايز","es-ES":"Raze","en-US":"Raze","de-DE":"Raze","ja-JP":"レイズ","ko-KR":"레이즈","fr-FR":"Raze","id-ID":"Raze","pl-PL":"Raze","pt-BR":"Raze","th-TH":"Raze","ru-RU":"Raze","tr-TR":"RAZE","vi-VN":"Raze","zh-CN":"雷兹","zh-TW":"芮茲"}'::jsonb, '{"es-MX":"Raze llega de Brasil con su explosiva personalidad y sus grandes armas. Gracias a su contundente estilo de juego, es muy buena para separar a los enemigos atrincherados y para despejar espacios estrechos con una gran cantidad de ''''bum''''.","it-IT":"La personalità della brasiliana Raze è esplosiva tanto quanto le sue armi. Con il suo stile di gioco brutale, è bravissima ad annientare i nemici trincerati e a liberare spazi angusti con una sana dose di \"boom\".","ar-AE":"أتت رايز بحيوية متفجرة من البرازيل مع تميزها بشخصية قوية وأسلحة كبيرة. أسلوب لعبها المائل إلى ضرب الأعداء عن قرب يجعلها تتفوق في إجبار الأعداء المتحصنين على الخروج من مكامنهم وكذلك في تطهير المساحات الضيقة باستخدام كميات كبيرة من المفرقعات.","es-ES":"Raze llega desde Brasil con ganas de hacer que todo salte por los aires. Con su estilo de juego basado en la fuerza bruta, destaca a la hora de barrer a grupos de enemigos atrincherados y de despejar áreas estrechas con explosión y sin compasión.","en-US":"Raze explodes out of Brazil with her big personality and big guns. With her blunt-force-trauma playstyle, she excels at flushing entrenched enemies and clearing tight spaces with a generous dose of \"boom.\"","de-DE":"Die explosive Raze bringt eine laute Persönlichkeit und dicke Knarren aus Brasilien mit. Durch ihre brachiale Spielweise ist sie besonders gut darin, Gegner aufzuscheuchen und beengte Räume mit einer großzügigen Portion „Bumm“ zu säubern.","ja-JP":"携えたキャノンと持ち前の個性を爆発させるレイズは故郷ブラジルを飛び出した。衝撃力でダメージを与えるスタイルを好む彼女は、「爆発」を惜しみなく使うことで守りを固めている敵を一掃したり、狭い場所をクリアリングすることに長けている。","ko-KR":"브라질에서 온 레이즈는 화끈한 성격으로 커다란 총기를 휘두릅니다. 그녀의 저돌적인 전투 스타일은 엄폐 중인 적을 몰아내는 데 적합하며 대량의 폭발물로 좁은 지역을 초토화합니다.","fr-FR":"Armée de sa personnalité et de sa grosse artillerie, Raze fait une entrée explosive depuis le Brésil. Grâce à sa force brute, elle excelle à débusquer les ennemis retranchés et à faire le ménage dans les espaces étroits, le tout avec une bonne dose de « boum ».","id-ID":"Raze, si eksplosif dari Brasil ini membawa kepribadian yang mencolok serta senjata besarnya. Dengan playstyle-nya yang brutal, Raze unggul dalam menyapu musuh yang berdiam dan mengosongkan ruang sempit dengan ledakan besar.","pl-PL":"Raze z Brazylii wkracza na pole walki ze swą wielką osobowością i wielkim arsenałem. Jej wybuchowy styl sprawia, że doskonale radzi sobie z okopanymi wrogami i czyszczeniem niewielkich przestrzeni za pomocą solidnej dawki eksplozji.","pt-BR":"Raze chega do Brasil com uma explosão de carisma e armas enormes. Com seu estilo de jogo \"porradeiro\", ela é craque em desentocar inimigos entrincheirados e limpar espaços apertados com uma bela dose de BUUUM!","th-TH":"Raze ระเบิดออกจากบราซิลด้วยบุคลิกที่เข้ากับคนอื่นได้ง่ายและปืนอันใหญ่โต ด้วยสไตล์การเล่นแบบถึงพริกถึงขิง เธอจึงเก่งกาจในการผลักดันศัตรูให้ออกจากที่มั่นและเคลียร์พื้นที่แคบพร้อมเสียง \"ตู้ม\" แบบหูดับตับไหม้","ru-RU":"Raze – мастер взрывного дела из Бразилии, обладательница сильного характера и еще более мощных пушек. Она способна легко справиться с засевшими в обороне противниками или зачистить небольшое помещение. Громко и без лишних церемоний.","tr-TR":"Bomba gibi bir kişiliğe ve kocaman silahlara sahip olan Raze, aramıza Brezilya''dan katılıyor. Kafa göz dalan oyun tarzıyla düşmanları saklandıkları deliklerden çıkarmakta ve dar alanları ''''bam bam bam'''' temizlemekte üstüne yoktur.","vi-VN":"Raze là một hiện tượng đến từ Brasil với cá tính nổi bật và những khẩu súng cực bự. Với lối chơi bùng nổ, cô luôn ép đối phương phải ra khỏi nơi ẩn nấp và dọn sạch đối thủ trong những địa hình chật hẹp với một liều thuốc nổ hạng nặng.","zh-CN":"“雷兹”来自亚马逊平原。她轰轰烈烈的性情就跟她手中的武器一样火爆，作战风格也是简单粗暴、爆发力十足。无论是攻坚战还是狭小空间的遭遇战，都是她的拿手好戏。","zh-TW":"來自巴西的芮茲經常使用巨型槍械展現她大剌剌的個性。她擅長用驚天一「砰」，逼出躲在壕溝的埋伏，掃除狹窄空間的敵人，這就是她的暴力破壞風。"}'::jsonb, 'Clay', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/displayicon.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/displayicon.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/killfeedportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/minimapportrait.png', null, 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/background.png', array['742e1eff', '0f1923ff', '2c5942ff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, '{"es-MX":"Chamber","it-IT":"Chamber","ar-AE":"تشامبر","es-ES":"Chamber","en-US":"Chamber","de-DE":"Chamber","ja-JP":"チェンバー","ko-KR":"체임버","fr-FR":"Chamber","id-ID":"Chamber","pl-PL":"Chamber","pt-BR":"Chamber","th-TH":"Chamber","ru-RU":"Chamber","tr-TR":"CHAMBER","vi-VN":"Chamber","zh-CN":"尚勃勒","zh-TW":"錢博爾"}'::jsonb, '{"es-MX":"Vestido y armado para matar, el diseñador de armas francés, Chamber, rechaza toda ofensiva con precisión letal. Aprovecha su arsenal personalizado para mantener a los enemigos a raya y eliminarlos desde lejos. Siempre cuenta con la contingencia perfecta para cada plan.","it-IT":"Chamber, progettista di armi francese agghindato e armato di tutto punto, è un agente capace di togliere di mezzo gli avversari con precisione letale. Questo Guardiano sfrutta il suo arsenale personalizzato per mantenere la posizione ed eliminare i nemici da lontano, creando la strategia perfetta per ogni occasione.","ar-AE":"مع ملابسه الأنيقة وأسلحته الجاهزة، يطرد مصمم الأسلحة الفرنسي تشامبر المعتدين بدقة فتاكة. وهو يستغل ترسانة أسلحته المخصصة للتمسك بالمواقع واقتناص الأعداء من على بُعد، مع خطة طوارئ مصممة لكل ظرف.","es-ES":"El diseñador de armas francés, siempre bien vestido y bien pertrechado, expulsa a los agresores con precisión letal. Chamber aprovecha su arsenal personalizado para resistir, elimina enemigos a distancia y crea la contingencia perfecta para cada plan.","en-US":"Well-dressed and well-armed, French weapons designer Chamber expels aggressors with deadly precision. He leverages his custom arsenal to hold the line and pick off enemies from afar, with a contingency built for every plan.","de-DE":"Gut gekleidet und bewaffnet vertreibt der französische Waffendesigner Chamber Angreifer mit tödlicher Präzision. Mit seinem individuellen Arsenal behält er alles im Blick, schaltet Gegner aus der Ferne aus und hat für jeden Plan einen Plan B.","ja-JP":"装いも武器も一流に。フランスの武器デザイナーであるチェンバーは、致命的な精度で敵を撃ち抜く。特製の武器で相手の侵攻を阻み、遠距離から狙い撃て。完璧な策略は、あらゆる戦略を凌駕する。","ko-KR":"맵시 있는 모습으로 단단히 무장한 프랑스 무기 디자이너 체임버는 치명적인 정확도로 적을 몰아냅니다. 만일의 사태에 대한 모든 계획을 세운 그는 자신만의 커스텀 무기를 사용하여 전선을 사수하고 멀리서 적을 격퇴합니다.","fr-FR":"Aussi classe que bien équipé, le concepteur d''armes français Chamber repousse les assaillants avec une précision mortelle. Il met à profit son arsenal bien particulier pour tenir sa position et éliminer les ennemis de loin en prévoyant une solution aux défis posés par chaque stratégie.","id-ID":"Berpakaian rapi dan bersenjata lengkap, Chamber, yang juga merupakan desainer senjata dari Prancis, menghalau penyerang dengan presisi yang mematikan. Dia memanfaatkan persenjataan kustomnya untuk mempertahankan barisan dan menembak musuh dari jauh, dengan kontingensi yang tersusun untuk tiap rencana.","pl-PL":"Świetnie ubrany i równie dobrze uzbrojony francuski projektant broni Chamber neutralizuje wrogów z zabójczą precyzją. Wykorzystując niestandardowy arsenał, utrzymuje pozycję i z daleka eliminuje wrogów, a na każdą ewentualność ma plan awaryjny.","pt-BR":"Bem-vestido e armado até os dentes, o criador de armas francês Chamber coloca os inimigos para correr com precisão mortal. Use e abuse do arsenal personalizado dele para segurar posições e abater inimigos de longe, criando a defesa perfeita para qualquer plano.","th-TH":"แต่งกายครบชุด อาวุธจัดเต็ม Chamber นักออกแบบอาวุธชาวฝรั่งเศสยับยั้งผู้บุกรุกด้วยความแม่นยำแสนร้ายกาจ เขาใช้คลังแสงสั่งทำพิเศษของเขาเพื่ิอป้องกันพื้นที่ และเด็ดหัวศัตรูจากระยะไกล และมีแผนสำรองสำหรับทุกแผนการ","ru-RU":"Одет с иголочки и вооружен до зубов. Chamber, французский конструктор оружия, уничтожает врагов с поразительной точностью. Уникальные умения этого стража позволяют эффективно защищаться, нейтрализовать врагов издалека и продумывать любой план до мельчайших подробностей.","tr-TR":"Her daim şık ve tam teçhizat dolaşan Fransız silah tasarımcısı Chamber, ölümcül isabetliliğiyle rakipleri ortadan kaldırıyor. Özel yeteneklerini kullanarak görüş mesafesi sağlar, uzaktaki rakipleri avlar ve her plana mükemmel bir şekilde uyum sağlar.","vi-VN":"Với vẻ ngoài lịch lãm và trang bị tối tân, chuyên gia vũ khí Chamber đến từ nước Pháp sẽ truy quét đối thủ bằng sự chính xác tuyệt đối. Anh có thể tận dụng kho vũ khí chuyên biệt của mình để giữ vững chiến tuyến, bắn hạ kẻ địch từ xa với phương án dự phòng hoàn hảo dành cho mọi kế hoạch tác chiến.","zh-CN":"穿着考究、装备精良的西欧武器设计师“尚勃勒”非常擅长防守阵线。他会利用强大的自制武器从远处逼退妄图进犯的敌人，同时也会为自己的撤退和转移准备体面的应急方案。","zh-TW":"錢博爾是來自法國的武器設計師，他一身時尚、滿載武力，用致命的精準武器把侵略者一一驅逐。他的特製武器可以守住戰線，從遠處一一消滅敵人，即便作戰出了亂子，他也能優雅應變，臨危不亂。"}'::jsonb, 'Deadeye', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/displayicon.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/displayicon.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/killfeedportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/minimapportrait.png', null, 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/background.png', array['20435bff', '0f1923ff', '372d2bff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, '{"es-MX":"KAY/O","it-IT":"KAY/O","ar-AE":"كاي/أو","es-ES":"KAY/O","en-US":"KAY/O","de-DE":"KAY/O","ja-JP":"KAY/O","ko-KR":"케이/오","fr-FR":"KAY/O","id-ID":"KAY/O","pl-PL":"KAY/O","pt-BR":"KAY/O","th-TH":"KAY/O","ru-RU":"KAY/O","tr-TR":"KAY/O","vi-VN":"KAY/O","zh-CN":"K/O","zh-TW":"KAY/O"}'::jsonb, '{"es-MX":"KAY/O es una máquina de guerra construida para un único propósito: neutralizar radiantes. Su poder para suprimir las habilidades enemigas neutraliza la capacidad de sus rivales para contraatacar, un aspecto que le da a él y a sus aliados la ventaja definitiva en la batalla.","it-IT":"KAY/O è una macchina da guerra costruita per un solo scopo: neutralizzare i radianti. La sua capacità di SOPPRIMERE le abilità nemiche compromette le possibilità di risposta degli avversari, dando un enorme vantaggio a lui e ai suoi alleati.","ar-AE":"كاي/أو هو آلة حربية مصممة لغرض واحد هو القضاء على الراديانتس. تتكفل قوة قَمع الأعداء لديه بتفكيك قدرة خصومه على المقاومة بالقتال، مما يؤمن له ولحلفائه الأفضلية الحاسمة.","es-ES":"KAY/O es una máquina de guerra construida con un único propósito: neutralizar a los radiantes. Su poder para suprimir habilidades enemigas incapacita a sus adversarios, lo que asegura la ventaja para él y sus aliados.","en-US":"KAY/O is a machine of war built for a single purpose: neutralizing radiants. His power to Suppress enemy abilities dismantles his opponents'' capacity to fight back, securing him and his allies the ultimate edge.","de-DE":"KAY/O ist eine Kriegsmaschine mit nur einem Zweck:  die Neutralisierung von Radiants. Er kann gegnerische Fähigkeiten unterdrücken, womit er Gegenangriffe effektiv verhindert und sich und seinen Verbündeten so den entscheidenden Vorteil verschafft.","ja-JP":"KAY/O はレディアントの制圧を目的として作られた戦闘兵器だ。その力で敵のアビリティーを封じ込め、反撃の機会を奪うことで、味方の絶対的優位を確保することができる。","ko-KR":"케이/오는 레디언트를 무력화하려는 단 하나의 목적을 위해 만들어진 전쟁 병기입니다. 자신과 아군이 유리하도록 적의 스킬을 억제하여 상대의 반격 능력을 약화시킵니다.","fr-FR":"KAY/O est une machine de guerre conçue dans un but précis : neutraliser les radiants. La neutralisation des compétences ennemies réduit les possibilités de riposte des adversaires, ce qui confère un avantage décisif à son équipe.","id-ID":"KAY/O adalah mesin perang yang dibuat untuk melumpuhkan para radiant. Kekuatannya dalam memberi utilitas Suppress pada ability musuh dapat mencegah mereka untuk melawan balik. Ini memberikan keunggulan besar bagi dirinya dan sekutunya.","pl-PL":"KAY/O to maszyna wojenna zbudowana w jednym celu: likwidowanie Promienistych. Jego moc tłumienia wrogich umiejętności ogranicza bojowe możliwości przeciwników, zapewniając KAY/O i jego sojusznikom niesamowitą przewagę.","pt-BR":"KAY/O é uma máquina de guerra construída com um único propósito: neutralizar Radiantes. Ele é capaz de Suprimir habilidades inimigas, anulando a capacidade de contra-ataque dos adversários e dando a si próprio e a seus aliados uma vantagem essencial em combate.","th-TH":"KAY/O เป็นจักรกลสงครามที่ถูกสร้างขึ้นเพื่อวัตถุประสงค์เดียว: กำจัด Radiant ความสามารถในการยับยั้งสกิลของศัตรูจะทำลายการตอบโต้จากคู่ต่อสู้ และทำให้เขาและเพื่อนร่วมทีมเอาชนะศึกไปได้ในที่สุด","ru-RU":"KAY/O – боевая машина, созданная лишь для одной цели: истребить радиантов. Его способность подавлять умения врага существенно ослабляет команду противника и обеспечивает преимущество союзникам.","tr-TR":"KAY/O, Radyantları etkisiz hale getirmek için üretilmiş bir savaş makinesi. Düşmanlarının yeteneklerini Sindirerek karşı koyma yetilerini bastırır. Böylece hem kendisini hem de takım arkadaşlarını korur.","vi-VN":"KAY/O là một cỗ máy chiến tranh được chế tạo vì 1 mục đích duy nhất: vô hiệu hóa kẻ thù. Khả năng Áp Chế kỹ năng của kẻ địch khiến chúng không thể phản kháng chắc chắn sẽ mang đến lợi thế lớn cho KAY/O và đồng đội khi giao chiến.","zh-CN":"K/O是一台战争机器，他被制造出来只有一个目的：消灭源能者。他的能力可以【压制】敌人的技能，为自己与队友制造战术优势。","zh-TW":"KAY/O是一台戰爭機器，其唯一目的是消滅所有輻能者。他可以抑制對手的能力，讓敵人無力還擊，為自身陣營取得絕大優勢。"}'::jsonb, 'Grenadier', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/displayicon.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/displayicon.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/killfeedportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/minimapportrait.png', null, 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/background.png', array['1c2a69ff', '0f1923ff', '1a1e4bff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, '{"es-MX":"Skye","it-IT":"Skye","ar-AE":"سكاي","es-ES":"Skye","en-US":"Skye","de-DE":"Skye","ja-JP":"スカイ","ko-KR":"스카이","fr-FR":"Skye","id-ID":"Skye","pl-PL":"Skye","pt-BR":"Skye","th-TH":"Skye","ru-RU":"Skye","tr-TR":"SKYE","vi-VN":"Skye","zh-CN":"斯凯","zh-TW":"絲凱"}'::jsonb, '{"es-MX":"Procedentes de Australia, Skye y su manada de bestias se abren paso por territorio hostil. Con sus creaciones que obstaculizan al enemigo y su poder para sanar a los demás, los equipos serán más fuertes y seguros al lado de Skye.","it-IT":"L''australiana Skye e il suo branco di animali aprono la strada nel territorio ostile. Con le sue creazioni, che ostacolano il nemico, e le sue capacità curative, la squadra è più forte e più al sicuro al fianco di Skye.","ar-AE":"تتولى سكاي، القادمة من أستراليا، بصحبة أصدقائها من الحيوانات فتح الطريق أمام الفريق في أراضي العدو. مع تكفل كائناتها بإعاقة مخططات العدو، وتمتعها بالقدرة على معالجة الآخرين، يبدو أي فريق أقوى وأكثر أمنًا بوجود سكاي في صفوفه.","es-ES":"Skye y su manada de bestias se abren paso desde Australia y a través de territorio hostil. Sus creaciones obstaculizan los avances enemigos y su capacidad para curar a los demás se ocupa de que, a su lado, su equipo esté a salvo.","en-US":"Hailing from Australia, Skye and her band of beasts trailblaze the way through hostile territory. With her creations hampering the enemy, and her power to heal others, the team is strongest and safest by Skye''s side.","de-DE":"Die Australierin Skye und ihr Rudel bahnen einen Weg durch gegnerisches Gebiet für das Team. Ihre Geschöpfe behindern den Gegner und durch ihre Heilkräfte kann ihrem Team nichts zustoßen, solange es an ihrer Seite ist.","ja-JP":"オーストラリアからやってきたスカイは、獣たちとともに敵陣への道を切り開く。スカイは敵を妨害する創造物を生み出すほか、味方を回復する力を持っている。彼女と行動をともにすることで、チームは最小のリスクで最大の力を発揮することができる。","ko-KR":"호주 출신의 스카이는 야수 떼와 함께 적대적인 영역에서 길을 개척합니다. 자신의 창조물로 적을 방해하고, 치유력으로 아군을 회복시키며 든든하게 팀을 지원합니다.","fr-FR":"Originaire d''Australie, Skye et sa bande de bêtes sauvages ouvrent la voie à travers les territoires hostiles. Grâce à ses créations qui entravent l''ennemi et à sa faculté à soigner les autres, l''équipe est plus forte et plus en sécurité quand elle compte Skye dans ses rangs.","id-ID":"Berasal dari Australia, Skye dan kawanannya yang buas berjalan menyusuri wilayah-wilayah berbahaya. Dia mampu memberikan heal, sementara makhluk ciptaannya dapat menghambat gerak musuh. Ini menjadikan dirinya adalah tempat paling aman dan kuat bagi para anggota timnya.","pl-PL":"Pochodząca z Australii Skye oraz sfora jej bestii utorują drogę przez terytorium wroga. Osłabiające wroga stwory oraz moc leczenia innych sprawią, że Skye wzmocni drużynę i zapewni jej większe bezpieczeństwo.","pt-BR":"Mandando um salve direto da Austrália, Skye e sua equipe de feras desbravam territórios hostis. Com seus poderes de cura e suas criações que partem pra cima dos inimigos, qualquer equipe ficará mais forte e mais segura tendo Skye como aliada.","th-TH":"เสียงกู่ร้องแห่งออสเตรเลีย Skye และเหล่าสัตว์ร้ายของเธอ แผดเผาเส้นทางศัตรูให้ลุกโชน ทีมของคุณจะแข็งแกร่งและปลอดภัยที่สุดเมื่ออยู่เคียงข้าง Skye เธอมาพร้อมกับสิ่งประดิษฐ์ที่ใช้ขัดขวางศัตรู และพลังการฮีลผู้อื่น","ru-RU":"Австралийка Skye и ее звериная стая прокладывают путь по враждебной территории. Ее создания затрудняют продвижение врага, а сама Skye может лечить союзников. С ней команда будет в безопасности и станет сильнее, чем когда-либо.","tr-TR":"Aramıza Avustralya''dan katılan Skye, beraberinde getirdiği vahşi hayvan ordusuyla birlikte çatışmayı iyiden iyiye kızıştırıyor. Düşmana ayak bağı olan hayvanları ve takım arkadaşlarını iyileştirme yetisiyle, takımının gücünü pekiştiriyor ve takımdaki herkesi kolluyor.","vi-VN":"Đến từ nước Úc hoang dã, Skye cùng các tinh linh của mình sẽ mở đường đột phá dũng mãnh trong những lãnh địa nguy hiểm. Với dàn tạo vật phong phú có nhiệm vụ quấy rối kẻ địch cùng khả năng hồi máu, cô sẽ luôn mang đến cho đồng đội sự an toàn và cho phép họ thỏa sức chiến đấu ở phong độ cao nhất.","zh-CN":"“斯凯”来自大洋洲，带着宠物风风火火地穿越敌人领地是她的标志风格。她不仅可以用她的造物牵制敌人，还能治疗队友，是小队中攻守兼备的一员。","zh-TW":"絲凱來自澳洲，她與她的野獸同伴會勇闖敵區為我方開路。除了能召喚生物妨礙敵軍，她還能治療隊友，因此只要有絲凱在側，肯定能展現隊伍的最強實力，避開凶險局面。"}'::jsonb, 'Guide', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/displayicon.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/displayicon.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/killfeedportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/minimapportrait.png', null, 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/background.png', array['436a51ff', '0f1923ff', '4f1413ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, '{"es-MX":"Cypher","it-IT":"Cypher","ar-AE":"سايفر","es-ES":"Cypher","en-US":"Cypher","de-DE":"Cypher","ja-JP":"サイファー","ko-KR":"사이퍼","fr-FR":"Cypher","id-ID":"Cypher","pl-PL":"Cypher","pt-BR":"Cypher","th-TH":"Cypher","ru-RU":"Cypher","tr-TR":"CYPHER","vi-VN":"Cypher","zh-CN":"零","zh-TW":"瑟符"}'::jsonb, '{"es-MX":"Cypher, el agente de inteligencia marroquí, es un sistema de vigilancia de un solo hombre que puede monitorear todos los movimientos de sus enemigos. No hay secreto que no descubra ni maniobra que no detecte. Cypher siempre está vigilando.","it-IT":"Il mercante d''informazioni marocchino Cypher agisce come una rete di sorveglianza che tiene sotto controllo ogni mossa del nemico. Nessun segreto è al sicuro. Nessuna manovra passa inosservata. Cypher è sempre all''erta.","ar-AE":"يعتبر سمسار المعلومات المغربي المعروف باسم سايفر شبكة مراقبة في رجل واحد قادر على رصد كل تحركات الأعداء. لا يخفى عليه أي سر. ولا تنطلي عليه أي حيلة. سايفر يقظ دائمًا.","es-ES":"Cypher es un experto en información de Marruecos que se especializa en redes de vigilancia y es capaz de seguirle la pista al enemigo constantemente. No hay secreto a salvo ni maniobra que pase desapercibida. Cypher siempre está alerta.","en-US":"The Moroccan information broker, Cypher is a one-man surveillance network who keeps tabs on the enemy''s every move. No secret is safe. No maneuver goes unseen. Cypher is always watching.","de-DE":"Der marokkanische Informationshändler Cypher ist ein Ein-Mann-Überwachungskommando, das die Bewegungen des Gegners genau im Blick behält. Kein Geheimnis ist sicher. Kein Manöver bleibt unbeobachtet. Cypher entgeht nichts.","ja-JP":"モロッコの情報屋、サイファーは敵のあらゆる動きを監視する、いわば「一人監視網」である。どんな秘密も安全ではない。どんな企みも見逃されることはない。どんな時もサイファーは見ているのだ。","ko-KR":"걸어 다니는 감시망이라고도 할 수 있는 모로코 출신의 정보 브로커 사이퍼는 적의 움직임과 정보를 끊임없이 감시합니다. 어떤 비밀이나 속임수를 감추고 있든 끈질기고 날카로운 사이퍼의 시선을 피할 방법은 없습니다.","fr-FR":"Véritable réseau de surveillance à lui tout seul, le vendeur d''informations marocain Cypher est capable de traquer les moindres déplacements de l''ennemi. Il révèle tous les secrets. Il détecte toutes les manœuvres. Rien n''échappe à Cypher.","id-ID":"Seorang perantara informasi dari Maroko, Cypher, adalah jaringan pengintai yang dioperasikan satu orang yang mengawasi tiap gerakan musuh. Tidak ada rahasia yang aman. Tidak ada manuver yang tidak terlihat. Cypher selalu mengawasi.","pl-PL":"Cypher, marokański broker informacji, to jednoosobowa sieć inwigilacyjna, pozwalająca śledzić wszelkie poczynania wroga. Żadna tajemnica nie jest bezpieczna. Nikt nie przejdzie niezauważony. Cypher zawsze obserwuje.","pt-BR":"Cypher, um vendedor de informações do Marrocos, é uma verdadeira rede de vigilância de um homem só que fica de olho em cada movimento dos inimigos. Nenhum segredo está a salvo. Nenhuma manobra passa despercebida. Cypher está sempre vigiando.","th-TH":"Cypher นายหน้าค้าข้อมูลแห่งโมร็อกโก เขาเป็นหน่วยเฝ้าระวังที่ทำงานเพียงลำพังเพื่อตามติดความเคลื่อนไหวของศัตรูในทุกย่างก้าว ไม่มีความลับใดที่ปลอดภัย ไม่มีการซ่อนเร้นไหนที่รอดพ้นสายตาของเขา เพราะ Cypher นั้นจับจ้องอยู่เสมอ\n","ru-RU":"Торговец информацией из Марокко Cypher может самостоятельно создать целую информационную сеть для отслеживания действий противника. Под неусыпным взором Cypher все тайное становится явным.","tr-TR":"Faslı bilgi uzmanı ve tek kişilik gözetleme ağı Cypher, düşmanın her hareketini bilir. Her sırrını duyar. Her manevrasını görür. Cypher''ın gözleri hep üzerinizdedir.","vi-VN":"Là một chuyên gia môi giới thông tin người Ma-rốc. Cypher có thể theo dõi mọi di chuyển của đối thủ với hệ thống giám sát tinh vi của mình. Mọi bí mật đều sẽ bị phát hiện. Mọi bước đi đều sẽ bị phát giác. Không gì có thể lọt khỏi mắt của Cypher.","zh-CN":"情报贩子“零”来自直布罗陀海峡南岸，他堪比人形情报网络，紧密地监视着敌人的一举一动。在他的眼皮底下没有秘密，也没有人能瞒天过海。","zh-TW":"瑟符是摩洛哥的情報販子，隻身一人便是頂尖情報中心，窺探著敵人的一舉一動。沒有機密是安全的，沒有計謀可以逃過他的法眼。瑟符永遠監視著你。"}'::jsonb, 'Gumshoe', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/displayicon.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/displayicon.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/killfeedportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/minimapportrait.png', null, 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/background.png', array['2f5078ff', '0f1923ff', '3f3f6cff', '0f192300'], true, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, '{"es-MX":"Sova","it-IT":"Sova","ar-AE":"سوفا","es-ES":"Sova","en-US":"Sova","de-DE":"Sova","ja-JP":"ソーヴァ","ko-KR":"소바","fr-FR":"Sova","id-ID":"Sova","pl-PL":"Sova","pt-BR":"Sova","th-TH":"Sova","ru-RU":"Sova","tr-TR":"SOVA","vi-VN":"Sova","zh-CN":"猎枭","zh-TW":"蘇法"}'::jsonb, '{"es-MX":"Proveniente de la tundra del eterno invierno de Rusia, Sova rastrea, encuentra y elimina a sus enemigos con gran eficiencia y precisión. Su arco personalizado y sus increíbles habilidades de exploración impedirán que sus enemigos puedan esconderse de él. ","it-IT":"Nato tra le nevi perenni della tundra russa, Sova insegue, trova ed elimina i nemici con precisione e spietata efficienza. Il suo arco modificato, combinato alle sue incredibili doti da ricognitore, lo rendono un cacciatore implacabile. ","ar-AE":"مع ولادته من رحم الشتاء الأزلي المخيم على سهول التندرا في روسيا، يقوم سوفا بالبحث وتقفي الأثر والقضاء على الأعداء بكفاءة ودقة فائقتين. قوسه المصنوع خصيصًا من أجله وقدراته الاستطلاعية المدهشة يضمنان أنك تستطيع الهرب، ولكن لن يمكنك أبدًا الاختباء منه.","es-ES":"Nacido en el eterno invierno de la tundra rusa, Sova destaca a la hora de localizar, perseguir y eliminar a los enemigos con una eficiencia y una precisión inclementes. Su arco personalizado junto con su sobrenatural capacidad de rastreamiento hacen que sea imposible escapar. ","en-US":"Born from the eternal winter of Russia''s tundra, Sova tracks, finds, and eliminates enemies with ruthless efficiency and precision. His custom bow and incredible scouting abilities ensure that even if you run, you cannot hide. ","de-DE":"Sova stammt aus dem ewigen Winter der russischen Tundra und verfolgt, findet und eliminiert Gegner mit gnadenloser Effizienz und Präzision. Sein Spezialbogen und seine unglaublichen Späherfähigkeiten sorgen dafür, dass du zwar fliehen, aber nicht entkommen kannst. ","ja-JP":"とこしえの冬、ロシアの凍原で生まれたソーヴァは、冷徹かつ確実に敵を追跡、発見し、そして排除する。たとえ逃げようとしても、彼の特別製の弓と恐るべき偵察アビリティーから身を隠すことはできない。 ","ko-KR":"겨울이 끝없이 이어지는 러시아 툰드라 지대에서 온 소바는 적들을 추적하고 발견하는 능력이 뛰어나며 정밀하면서도 무자비하게 적을 섬멸합니다. 직접 제작한 활과 뛰어난 정찰 스킬은 숨어 있는 적도 놓치지 않습니다.","fr-FR":"Né dans l''hiver éternel de la toundra russe, Sova traque, trouve et élimine ses ennemis avec une efficacité et une précision redoutables. Ses incroyables talents d''éclaireur et son arc personnalisé lui garantissent que sa cible ne fuira jamais très longtemps. ","id-ID":"Terlahir di teritori tundra Rusia yang diselimuti musim dingin abadi, Sova dapat melacak, menemukan, dan menghabisi musuh dengan efisiensi serta akurasi yang dahsyat. Busur khusus dan ability pengintaiannya yang sangat kuat, dapat memastikan bahwa musuh bisa lari tetapi tidak bisa sembunyi. ","pl-PL":"Sova to urodzony w skutej wieczną zimą rosyjskiej tundrze tropiciel, który śledzi, namierza i eliminuje wrogów z bezwzględną skutecznością i precyzją. Jego niestandardowy łuk w połączeniu z niesamowitymi umiejętnościami tropiącymi sprawiają, że nie ma przed nim ucieczki. ","pt-BR":"Nascido sob o eterno inverno das tundras russas, Sova rastreia, encontra e elimina inimigos com eficiência e precisão implacáveis. Seu arco personalizado e suas habilidades inigualáveis de reconhecimento garantem que nenhuma presa escape. ","th-TH":"Sova เกิดในช่วงฤดูหนาวอันยาวนาน ณ ทุ้งทุนดราแห่งรัสเซีย เขาติดตาม ตามล่า กำจัดศัตรูได้อย่างเด็ดขาดและแม่นยำ ด้วยธนูพิเศษที่ดัดแปลงเอง พร้อมความสามารถในการล่าชั้นเลิศ ต่อให้คุณหนีไปสุดขอบฟ้าก็ไม่มีวันรอดพ้นจากเงื้อมมือของเขา","ru-RU":"Рожденный в вечной мерзлоте российского заполярья, Sova выслеживает и уничтожает противников с холодной расчетливостью и эффективностью. Этот первоклассный разведчик, экипированный особым луком, найдет вас, где бы вы ни прятались. ","tr-TR":"Rusya''nın uçsuz bucaksız tundralarında yetişen Sova düşmanlarını acımasız bir verimlilik ve titizlikle tespit eder, izlerini sürer ve onları yok eder. Özel yayı ve sıra dışı iz sürme yetenekleri ile ondan kaçsanız da asla saklanamazsınız. ","vi-VN":"Sinh ra tại vùng lãnh nguyên lạnh giá của nước Nga, Sova có khả năng tìm kiếm, đánh dấu và tiêu diệt đối thủ một cách hiệu quả và chính xác. Sở hữu cây cung đặc chế và những kỹ năng trinh sát hiểm hóc, con mồi của Sova sẽ chẳng bao giờ có thể trốn thoát. ","zh-CN":"”猎枭“生长于终年严寒的北方冻原。他能够精准而高效地追踪、锁定和歼灭敌人。凭借一把特制战弓和无与伦比的侦察能力，他能让猎物无所遁形、无处可逃。 ","zh-TW":"蘇法出生於俄羅斯的永凍冰原，他靠著快捷而精準的身手，緊追在後、曝光敵蹤、將目標無情殲滅。他手持改造弓，結合出色的偵察能力，讓你逃得了一時，躲不過一世。 "}'::jsonb, 'Hunter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/displayicon.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/displayicon.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/killfeedportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/minimapportrait.png', null, 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/background.png', array['355285ff', '0f1923ff', '101c47ff', '0f192300'], false, true, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, '{"es-MX":"Miks","it-IT":"Miks","ar-AE":"ميكس","es-ES":"Miks","en-US":"Miks","de-DE":"Miks","ja-JP":"ミクス","ko-KR":"믹스","fr-FR":"Miks","id-ID":"Miks","pl-PL":"Miks","pt-BR":"Miks","th-TH":"Miks","ru-RU":"Miks","tr-TR":"MIKS","vi-VN":"Miks","zh-CN":"迷核","zh-TW":"米克什"}'::jsonb, '{"es-MX":"Miks llega directo desde Croacia para apoderarse del escenario en una explosión de energía sonora. Con una pasión contagiosa y un poder supersónico, motiva al resto del equipo para que avance al unísono mientras marca el ritmo en el campo de batalla.","it-IT":"Direttamente dalla Croazia, Miks entra in scena sprigionando pura energia sonora. Con la sua passione contagiosa e i suoi poteri sonici, ispira la sua squadra ad agire all''unisono mentre tutti insieme dettano il ritmo sul campo di battaglia.","ar-AE":"من قلب كرواتيا، يعتلي ميكس المسرح مشعًا بطاقة صوتية صافية. وبحماسه المُعدي وقدراته الصوتية، يحشد أعضاء فرقته ليتحركوا بتناغم تام وهم يفرضون إيقاعهم معًا على ساحة المعركة.","es-ES":"Directo desde Croacia, Miks sube al escenario y canaliza energía sónica pura. Con su pasión contagiosa y sus poderes sónicos, reúne a su equipo para avanzar al unísono y seguir el ritmo juntos en el campo de batalla.","en-US":"Straight from Croatia, Miks takes the stage channeling pure sound energy. With his infectious passion and sonic powers, he rallies his squad to move as one as they set the tempo on the battlefield together.","de-DE":"Miks aus Kroatien betritt die Bühne und kanalisiert pure Soundenergie. Mit seiner ansteckenden Leidenschaft und seinen Schallkräften motiviert er sein Team, als Einheit zu agieren, während sie gemeinsam den Takt auf dem Schlachtfeld angeben.","ja-JP":"クロアチア出身のミクスは、純粋な音のエネルギーをまといステージに立つ。ほとばしる情熱と音の力で仲間を奮い立たせ、戦場にテンポを刻みながらチームをひとつに導く。","ko-KR":"크로아티아에서 온 믹스가 순수한 소리 에너지를 발산하며 무대에 오릅니다. 그는 전염성 강한 열정과 음파의 힘으로 분대원들을 하나로 뭉치게 하고, 함께 전장의 속도를 조절합니다.","fr-FR":"Tout droit venu de Croatie, Miks monte sur scène en canalisant une énergie sonore pure. Avec sa passion contagieuse et ses pouvoirs soniques, il rassemble son escouade pour avancer à l''unisson et donner le rythme sur le champ de bataille.","id-ID":"Langsung dari Kroasia, Miks naik ke panggung dengan menyalurkan energi suara murni. Dengan semangat yang menular dan kekuatan soniknya, dia menyatukan skuadnya untuk bergerak sebagai satu, mengatur tempo dan menguasai medan pertempuran bersama.","pl-PL":"Prosto z Chorwacji – Miks wchodzi na scenę, emanując czystą energią muzyki. Dzięki swojej zaraźliwej pasji i dźwiękowym mocom zagrzewa swój oddział do wspólnego działania, gdy razem nadają tempo na polu bitwy.","pt-BR":"Diretamente da Croácia, Miks sobe ao palco canalizando pura energia sonora. Com sua paixão contagiante e seus poderes sônicos, ele coordena o esquadrão para que todos se movam em sincronia, ditando juntos o ritmo do campo de batalha.","th-TH":"Miks ที่ส่งตรงจากโครเอเชีย พร้อมระเบิดพลังเสียงล้วน ๆ เพื่อขึ้นครองเวทีแล้ว ด้วยความมุ่งมั่นอันเร่าร้อนและพลังคลื่นเสียง เขาจะรวมทั้งทีมให้ลงมืออย่างพร้อมเพรียง คุมจังหวะในสนามรบไปด้วยกัน","ru-RU":"На сцену выходит Miks – агент из Хорватии и само воплощение силы звука. Своим оптимизмом и музыкальными способностями Miks побуждает команду действовать как единое целое и задает общий темп на поле боя.","tr-TR":"Hırvatistan''dan gelen Miks, saf ses enerjisini sahneye taşıyor. Bulaşıcı tutkusu ve ses dalgalarını kontrol eden güçleriyle ekibini birlikte hareket etmeye teşvik eder ve savaş alanının temposunu beraber değiştirirler.","vi-VN":"Thẳng tiến từ Croatia, Miks bước lên sân khấu, dẫn dắt nguồn năng lượng âm thanh thuần khiết. Với đam mê lan tỏa và sức mạnh sóng âm của mình, anh hiệu triệu đồng đội hòa nhịp như một thể thống nhất, cùng nhau thiết lập nhịp điệu trên chiến trường.","zh-CN":"来自欧洲中南部的“迷核”能够操控纯粹的声波能量。凭借极具感染力的激情和独特的音波力量，他率领全队协同作战，定下战场的主导节奏。","zh-TW":"來自克羅埃西亞的米克什登上舞台，釋放純粹的音浪能量。他憑藉充滿感染力的熱情和音樂的力量，帶領隊伍協同一心，主宰戰場節奏。"}'::jsonb, 'Iris', '2026-03-18T15:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/displayicon.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/displayicon.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/killfeedportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/minimapportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/background.png', array['462b75ff', '0f1923ff', '344673ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, '{"es-MX":"Killjoy","it-IT":"Killjoy","ar-AE":"كيلجوي","es-ES":"Killjoy","en-US":"Killjoy","de-DE":"Killjoy","ja-JP":"キルジョイ","ko-KR":"킬조이","fr-FR":"Killjoy","id-ID":"Killjoy","pl-PL":"Killjoy","pt-BR":"Killjoy","th-TH":"Killjoy","ru-RU":"Killjoy","tr-TR":"KILLJOY","vi-VN":"Killjoy","zh-CN":"奇乐","zh-TW":"愷宙"}'::jsonb, '{"es-MX":"La prodigio alemana Killjoy asegura fácilmente los puntos estratégicos del campo de batalla con su arsenal de inventos. Si el daño que inflige no detiene a sus enemigos, las debilitaciones de sus robots la ayudarán a aniquilarlos.","it-IT":"Killjoy, la teutonica geniale, conquista senza sforzo posizioni chiave sul campo di battaglia con il suo arsenale di invenzioni. Quando i suoi robot non bastano a eliminare direttamente i nemici, le consentono comunque di sbarazzarsene con facilità.","ar-AE":"تؤمّن كيلجوي، العبقرية الألمانية، البقع الحساسة في ميدان القتال دون جهد يُذكر بفضل ترسانة اختراعاتها. وإذا لم يتكفل الضرر الناجم عن الأدوات بقتل أعدائها، فإن المثبط الذي توفره روبوتاتها سيدمرهم بلا أدنى شك.","es-ES":"Killjoy es una brillante agente alemana que se encarga de tomar posiciones clave del campo de batalla con su arsenal de inventos. Si su daño no acaba con los enemigos, su horda de robots ayudarán a su equipo a despejarlos en un abrir y cerrar de ojos.","en-US":"The genius of Germany, Killjoy effortlessly secures key battlefield positions with her arsenal of inventions. If their damage doesn''t take her enemies out, the debuff her robots provide will make short work of them.","de-DE":"Das deutsche Genie Killjoy sichert mühelos Schlüsselpositionen auf dem Schlachtfeld mit ihrem Arsenal von Erfindungen. Wenn der Schaden die Gegner nicht ausschaltet, geben ihnen die von den Robotern verteilten Schwächungen den Rest.","ja-JP":"ドイツ出身の天才キルジョイは発明した兵器を操り、難なく戦場を掌握する。敵の動きを止めるのに武器によるダメージでは不十分なら、彼女のロボットを使ったデバフが敵の迅速な処理に一役買うだろう。","ko-KR":"독일의 천재 킬조이는 다양한 발명품을 사용해 전장의 주요 위치를 손쉽게 확보합니다. 발명품으로 적을 쓰러뜨릴 수는 없더라도 해로운 효과를 이용해 적을 단숨에 제압할 수 있습니다.","fr-FR":"Véritable génie originaire d''Allemagne, Killjoy sécurise et défend les positions clés sans effort grâce à son arsenal d''inventions. Si son équipement ne suffit pas à arrêter l''ennemi, ce sont les malus de ses robots qui en feront du menu fretin.","id-ID":"Sang genius dari Jerman, Killjoy, dengan mudah mengamankan posisi penting di battlefield dengan segudang penemuannya. Jika damage yang dihasilkan temuannya tidak menghentikan musuh, debuff robot-robotnya akan mengatasinya.","pl-PL":"Killjoy, genialna Niemka, z łatwością broni kluczowych pozycji na polu walki, korzystając ze swoich wynalazków. Jeśli sama nie wykończy swoich wrogów, osłabienia wywołane przez jej roboty z pewnością dokończą dzieła zniszczenia.","pt-BR":"Killjoy, uma alemã genial, defende posições-chave no campo de batalha facilmente com seu arsenal de invenções. Se o dano causado por seu equipamento não der cabo dos inimigos, os efeitos negativos de seus queridos robôs dão conta do recado.","th-TH":"Killjoy อัจฉริยะจากเยอรมนีเข้าควบคุมและป้องกันตำแหน่งสำคัญในสนามรบด้วยกองทัพสิ่งประดิษฐ์ของเธอ หากความเสียหายจากอุปกรณ์ของเธอหยุดศัตรูไม่ได้ ดีบัฟจากหุ่นยนต์ของเธอจะช่วยจัดการให้เอง","ru-RU":"Гений из Германии Killjoy с легкостью защищает территорию на поле боя с помощью своего арсенала изобретений. И если противники все же уцелеют, то эффекты ослабления помогут Killjoy добить их.","tr-TR":"Alman dâhi Killjoy, kendi icatlarından oluşan cephaneliğiyle savaş meydanını kontrol altına alır. Cihazlarının verdiği hasar rakiplerini durdurmaya yetmezse robotlarının yardımıyla rakiplerini zayıflatarak onların ortadan kaldırılmalarını kolaylaştırır.","vi-VN":"Một thiên tài từ nước Đức với hàng loạt những sáng chế độc đáo, Killjoy hoàn toàn dễ dàng bảo kê những vị trí quan trọng nhất để thống lĩnh chiến trường. Ngoài việc sở hữu thiết bị có sát thương khủng, kỹ năng làm suy yếu đối thủ từ các robot sẽ giúp cô chặn đứng mọi kẻ địch chỉ trong tích tắc.","zh-CN":"“奇乐”是来自莱茵河畔的天才发明家，她擅长使用陷阱、炮台和地雷来控制和防守战场上的关键位置。敌人若是不懂知难而退，便会发现这些装置个头虽小，制造的麻烦却很大。","zh-TW":"愷宙是位來自德國的天才，她擅長使用自己發明的多種武器，好整以暇地守住戰場上的重要點位，使敵人無法越雷池一步。這些武器就算沒把敵人立即擊倒，也足以靠著附加的減益效果使他們舉步維艱。"}'::jsonb, 'Killjoy', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/displayicon.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/displayicon.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/killfeedportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/minimapportrait.png', null, 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/background.png', array['522162ff', '0f1923ff', '413950ff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, '{"es-MX":"Harbor","it-IT":"Harbor","ar-AE":"هاربور","es-ES":"Harbor","en-US":"Harbor","de-DE":"Harbor","ja-JP":"ハーバー","ko-KR":"하버","fr-FR":"Harbor","id-ID":"Harbor","pl-PL":"Harbor","pt-BR":"Harbor","th-TH":"Harbor","ru-RU":"Harbor","tr-TR":"HARBOR","vi-VN":"Harbor","zh-CN":"海神","zh-TW":"哈泊"}'::jsonb, '{"es-MX":"Originario de las costas de la India, Harbor arrasa el campo de batalla utilizando tecnología ancestral que controla el agua. Desata corrientes furiosas y olas aplastantes para escudar aliados o apalear a sus oponentes.","it-IT":"Dalla costa dell''India, Harbor travolge il campo di battaglia brandendo un''antica tecnologia in grado di dominare l''acqua. Scatena rapide intense e onde travolgenti per proteggere i suoi alleati o colpire duramente i nemici.","ar-AE":"مع قدومه من سواحل الهند، يقتحم هاربور ميدان القتال حاملًا تحفة تقنية قديمة يهيمن بفضلها على القوى المائية. ويطلق تيارات مائية جامحة وأمواجًا ساحقة لتدريع حلفائه أو إغراق من يعترضون طريقه.","es-ES":"Desde las costas de la India, Harbor llega al campo de batalla armado con tecnología ancestral capaz de controlar el agua. Libera espumosos torrentes y demoledoras olas para escudar a sus aliados o machacar a quien se interponga en su camino.","en-US":"Hailing from India’s coast, Harbor storms the field wielding ancient technology with dominion over water. He unleashes frothing rapids and crushing waves to shield his allies, or pummel those that oppose him.","de-DE":"Harbor stürmt von Indiens Küsten mit uralter Technologie auf das Feld und beherrscht das Wasser. Er entfesselt Stromschnellen und Sturmfluten, mit denen er seine Verbündeten schützt oder seine Gegner auf Abstand hält.","ja-JP":"インド沿岸部からやってきたハーバーは、古代のテクノロジーによって水を巧みに操り、戦場に嵐を巻き起こす。ハーバーの繰り出す激流や荒波は、味方を守る盾にも、敵を打ち倒す一撃にもなるだろう。","ko-KR":"인도 해안에서 온 하버는 물을 조종하는 고대 기술로 전장을 휩씁니다. 거센 급류와 강력한 파도로 아군을 보호하거나 적을 공격합니다.","fr-FR":"Venu de la côte indienne, Harbor déferle sur le terrain grâce à une technologie antique qui lui permet de contrôler l''eau. Il déchaîne des torrents bouillonnants et de terribles lames d''eau pour protéger ses alliés et noyer ses adversaires.","id-ID":"Berasal dari pesisir India, Harbor menyerbu battlefield menggunakan teknologi kuno yang dapat mengendalikan air. Dia mengeluarkan arus deras berbuih dan ombak mematikan untuk melindungi sekutu, atau menghancurkan siapa pun yang menentangnya.","pl-PL":"Pochodzący z Indii Harbor bierze pole szturmem, dzierżąc starożytną technologię i władając wodą. Uwalnia dzikie prądy i miażdżące fale, by chronić swoich sojuszników i zalewać tych, którzy stają mu na drodze.","pt-BR":"Vindo do litoral indiano, Harbor entra em campo com a força da tormenta, empunhando tecnologia ancestral com domínio sobre a água. Ele libera corredeiras espumantes e ondas esmagadoras para proteger seus aliados ou atacar aqueles que se opõem a ele.","th-TH":"Harbor ผู้ล่องไหลมาจากชายฝั่งของอินเดียโถมเข้าสู่การต่อสู้พร้อมเทคโนโลยีโบราณที่กุมพลังเหนือสายน้ำ เขาจะปล่อยคลื่นกระแทกอันเชี่ยวกรากเพื่อปกป้องเหล่าพันธมิตร หรือจัดการผู้ที่กล้ามาต่อกรกับเขา","ru-RU":"Агент Harbor с индийского побережья обрушивает бурю на поле боя, используя древнюю технологию управления водой. Он повелевает бурлящими потоками и сокрушительными волнами, чтобы защитить союзников или разгромить противников.","tr-TR":"Hindistan''ın kıyılarından gelen Harbor, kadim teknolojilerle suya hükmederek sahada fırtınalar koparıyor. Dostlarını korumak ve düşmanlarını alt etmek için güçlü akıntılar ve coşkun dalgalar çağırıyor.","vi-VN":"Xuất thân từ vùng bờ biển của Ấn Độ, Harbor nhấn chìm chiến trường bằng thứ công nghệ cổ xưa có khả năng điều khiển nước. Hắn tung ra những ngọn thác hung dữ và những con sóng bạc đầu để bảo hộ cho đồng đội hoặc đè bẹp kẻ thù.","zh-CN":"“海神”来自印度洋沿岸，借助古代科技的力量，他能够灵活地控制水的形态，释放出激流和巨浪来保护队友或击溃敌人。","zh-TW":"哈泊來自印度沿岸地區，他操縱著古代科技，支配水的力量，如潮水般洶湧衝上戰場。他會放出水沫四濺的湍流和勢不可擋的浪潮，給予友軍護盾，並狠狠擊潰敵軍。"}'::jsonb, 'Mage', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/displayicon.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/displayicon.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/killfeedportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/minimapportrait.png', null, 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/background.png', array['275146ff', '0f1923ff', '11434eff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, '{"es-MX":"Vyse","it-IT":"Vyse","ar-AE":"فايس","es-ES":"Vyse","en-US":"Vyse","de-DE":"Vyse","ja-JP":"ヴァイス","ko-KR":"바이스","fr-FR":"Vyse","id-ID":"Vyse","pl-PL":"Vyse","pt-BR":"Vyse","th-TH":"Vyse","ru-RU":"Vyse","tr-TR":"VYSE","vi-VN":"Vyse","zh-CN":"维斯","zh-TW":"薇絲"}'::jsonb, '{"es-MX":"Vyse, la mente maestra metálica, libera metal líquido para aislar, atrapar y desarmar a sus enemigos. Mediante su astucia y manipulación, obliga a quienes se opongan a ella a temerle al campo de batalla mismo.","it-IT":"La dominatrice del metallo Vyse scatena un metallo liquido che isola, intrappola e disarma i suoi nemici. Con astuzia e manipolazione, costringe chi le si oppone a temere anche il campo di battaglia.","ar-AE":"تطلق خبيرة المعادن فايس المعدن السائل لعزل الأعداء والإيقاع بهم وتجريدهم من أسلحتهم. بفضل ذكائها الحاد وقدرتها على التلاعب، تجعل جميع خصومها يخشون ساحة المعركة نفسها.","es-ES":"La prodigiosa ferromante Vyse crea metal en estado líquido para aislar, atrapar y desarmar a sus enemigos. Gracias a su astucia y poder de manipulación, fuerza a sus oponentes a desconfiar incluso del campo de batalla.","en-US":"Metallic mastermind Vyse unleashes liquid metal to isolate, trap, and disarm her enemies. Through cunning and manipulation, she forces all who oppose her to fear the battlefield itself.","de-DE":"Das metallmanipulierende Genie Vyse entfesselt flüssiges Metall, um damit ihre Gegner zu isolieren, festzusetzen und zu entwaffnen. Wer sich ihr widersetzt, wird das Schlachtfeld selbst fürchten, wenn sie mit ihren fiesen Tricks und Manipulationen anrückt.","ja-JP":"金属を操る戦術家であるヴァイスは、液体金属を駆使して敵を孤立させ、罠にかけて無力化する。狡猾さと策略によって敵を操り、戦場そのものを恐れさせる。","ko-KR":"강철 장인 바이스는 액체 금속을 사용하여 적을 고립시키고, 함정에 빠뜨리고, 무력화합니다. 그 간계와 술수를 본 적들은 전장 자체를 두려워하게 됩니다.","fr-FR":"La génie du métal Vyse utilise le métal liquide pour isoler, piéger et désarmer ses ennemis. Par la ruse et la manipulation, elle force tous ses adversaires à craindre le champ de bataille lui-même.","id-ID":"Mastermind metalik Vyse mengeluarkan logam cair untuk mengisolasi, menjebak, dan melucuti senjata musuh-musuhnya. Dengan kelicikan dan manipulasi, dia memaksa semua yang menentangnya untuk takut memasuki battlefield.","pl-PL":"Genialna metalurgiczka Vyse wykorzystuje ciekły metal do izolowania, więzienia i rozbrajania wrogów. Dzięki swojemu sprytowi i zdolnościom manipulacji zmusza wszystkich, którzy się jej sprzeciwiają, by lękali się już samego pola bitwy.","pt-BR":"A mestre dos metais Vyse usa metal líquido para isolar, prender e desarmar os inimigos. Com astúcia e manipulação, ela faz todos os adversários que a enfrentam temerem o próprio campo de batalha.","th-TH":"จอมบงการแห่งโลหะ Vyse จะใช้โลหะเหลวเพื่อแยกกัก ดักจับ และปลดอาวุธเหล่าศัตรูของเธอ เธออาศัยเล่ห์เหลี่ยมและการปั่นประสาท เพื่อฝังความกลัวแม้กระทั่งการเดินในสนามรบลงในหัวของเหล่าศัตรูของเธอ","ru-RU":"Vyse умеет управлять жидким металлом, запирая, пленяя и обезоруживая врагов с его помощью. Хитростью и мастерством она вынудит любого, кто встанет на ее пути, бояться самого поля боя.","tr-TR":"Vyse sıvı metali kontrol ederek düşmanlarını sürüden ayıran, tuzağa düşüren ve silahsız bırakan bir dâhi. Kurnazlığı ve manipülasyon kabiliyeti sayesinde karşısına çıkanları bizzat savaş alanının kendisinden korkar hale getirir.","vi-VN":"Vyse - bậc thầy kim loại, có khả năng sử dụng thép lỏng để cô lập, gài bẫy và khóa vũ khí của kẻ địch. Với chiến lược xảo quyết và kỹ năng kiểm soát tàng hình, cô sẽ khiến mọi kẻ địch phải nếm mùi kinh hãi của chiến trường.","zh-CN":"“维斯”是一位高智商金属能力者。她能自由操纵液态金属的形态，为敌人设下重重陷阱和障碍，甚至解除他们的武装。敌人与她对抗，就像在与整个战场为敌。","zh-TW":"善於謀略與操縱金屬的薇絲能釋放液態金屬來隔絕、誘捕敵軍，甚至卸除其武裝。工於心計的她能輕易操控對手心智，讓戰場成為恐懼的代名詞。"}'::jsonb, 'Nox', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/displayicon.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/displayicon.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/killfeedportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/minimapportrait.png', null, 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/background.png', array['492280ff', '0f1923ff', 'ffffffff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, '{"es-MX":"Viper","it-IT":"Viper","ar-AE":"فايبر","es-ES":"Viper","en-US":"Viper","de-DE":"Viper","ja-JP":"ヴァイパー","ko-KR":"바이퍼","fr-FR":"Viper","id-ID":"Viper","pl-PL":"Viper","pt-BR":"Viper","th-TH":"Viper","ru-RU":"Viper","tr-TR":"VIPER","vi-VN":"Viper","zh-CN":"蝰蛇","zh-TW":"薇蝮"}'::jsonb, '{"es-MX":"Viper, la química estadounidense, despliega un arsenal químico y venenoso para controlar el campo de batalla y reducir la visión de sus enemigos. Si las toxinas no matan a su presa, sin duda sus juegos mentales lo harán.","it-IT":"La scienziata americana Viper ha una serie di dispositivi chimici velenosi con i quali controlla il campo di battaglia e blocca la visione nemica. Se le tossine non uccidono la sua preda, lo faranno i suoi giochetti mentali.","ar-AE":"تنشر الكيميائية الأمريكية المعروفة باسم فايبر مجموعة من الأجهزة الكيميائية السامة للتحكم بميدان القتال وخنق قدرة العدو على الرؤية. وتتكفل أساليب خداعها البارعة بقتل فريستها إن لم تنجح سمومها في تحقيق ذلك.","es-ES":"Viper es una química estadounidense con un amplio arsenal de dispositivos venenosos que le sirven para tomar el control del campo de batalla y cegar a los enemigos. Si las toxinas no acaban con su presa, la paranoia la rematará.","en-US":"The American Chemist, Viper deploys an array of poisonous chemical devices to control the battlefield and choke the enemy''s vision. If the toxins don''t kill her prey, her mindgames surely will.","de-DE":"Die US-amerikanische Chemikerin Viper setzt eine Reihe von Geräten mit giftigen Chemikalien ein, um die Kontrolle über das Schlachtfeld zu behalten und dem Gegner die Sicht zu nehmen. Falls das Gift ihre Beute nicht zur Strecke bringt, erledigen ihre Psychospielchen das Übrige.","ja-JP":"アメリカ合衆国の化学者であるヴァイパーは、危険な化学兵器を駆使して戦況を巧みに操り、敵の視界を妨げることができる。仮にその標的が毒で力尽きなかったとしても、彼女が仕掛ける心理戦の毒牙から逃れることはできないのだ。","ko-KR":"미국 출신 화학자 바이퍼는 다양한 화학 무기로 전장을 장악하고 적의 시야를 차단합니다. 화학 공격으로부터 살아남는다고 해도 바이퍼의 심리전에 놀아날 뿐입니다.","fr-FR":"Viper est une chimiste américaine qui déploie un arsenal d''appareils toxiques pour contrôler le champ de bataille et entraver la vision des ennemis. Si les toxines ne suffisent pas à abattre sa proie, ses machinations finiront le travail.","id-ID":"Seorang Ahli Kimia dari Amerika, Viper, mengerahkan sejumlah perangkat kimia beracun untuk mengendalikan battlefield dan menghalangi pandangan musuh. Jika racun tidak membunuh musuhnya, permainan pikirannya pasti menghabisi mereka.","pl-PL":"Amerykańska chemiczka Viper wykorzystuje urządzenia z trującymi chemikaliami, by kontrolować pole walki i ograniczać wizję wroga. Jeśli nie wykończy ofiary toksynami, z pewnością zrobi to psychologicznie.","pt-BR":"Viper, a química dos Estados Unidos, emprega uma variedade de dispositivos químicos venenosos para controlar o campo de batalha e prejudicar a visão do inimigo. Se as toxinas não matarem a presa, seus jogos mentais certamente o farão.","th-TH":"Viper นักเคมีสาวชาวอเมริกันใช้อุปกรณ์ทางเคมีที่เป็นพิษเพื่อควบคุมสนามรบและบดบังทัศนวิสัยของศัตรู หากเหยื่อของเธอไม่ได้ตายด้วยพิษ ก็ตายด้วยสงครามจิตวิทยาเนี่ยแหละ","ru-RU":"Химик из США Viper устанавливает контроль над полем боя с помощью источающих токсичный газ устройств и ограничивает обзор противникам. А тех, кого ей не удастся отравить, она непременно перехитрит.","tr-TR":"Amerikalı kimyager Viper zehir yüklü, çeşit çeşit kimyasal cihazıyla savaş alanını kontrol altında tutarken düşmanın görüşünü de sekteye uğratır. Avını zehriyle değilse bile aklıyla mutlaka avcunun içine alır.","vi-VN":"Là Chuyên Gia Hóa Học người Mỹ, Viper tung ra một loạt các thiết bị hóa học độc hại để kiểm soát chiến trường và bóp nghẹt tầm nhìn của đối thủ. Nếu kẻ địch không bị tiêu diệt bởi chất độc thì cũng mất mạng bởi tâm thuật của cô.","zh-CN":"“蝰蛇”是一位来自美洲大陆的化学家，擅长部署毒性化学装置来控制战场并削弱敌人的视野。即便猎物没倒在她的毒素之下，她也会利用心理战将其击溃。","zh-TW":"薇蝮是名美國化學家，她的特長是部署五花八門的劇毒化武，掌控戰局的同時，還能妨礙敵人視野。即使毒藥沒能殺死對手，她的心理戰術也會虐死人。"}'::jsonb, 'Pandemic', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/displayicon.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/displayicon.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/killfeedportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/minimapportrait.png', null, 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/background.png', array['1a5f46ff', '0f1923ff', '2c4f5eff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('eb93336a-449b-9c1b-0a54-a891f7921d69'::uuid, '{"es-MX":"Phoenix","it-IT":"Phoenix","ar-AE":"فينيكس","es-ES":"Phoenix","en-US":"Phoenix","de-DE":"Phoenix","ja-JP":"フェニックス","ko-KR":"피닉스","fr-FR":"Phoenix","id-ID":"Phoenix","pl-PL":"Phoenix","pt-BR":"Phoenix","th-TH":"Phoenix","ru-RU":"Phoenix","tr-TR":"PHOENIX","vi-VN":"Phoenix","zh-CN":"不死鸟","zh-TW":"菲尼克斯"}'::jsonb, '{"es-MX":"Phoenix proviene del Reino Unido. El poder estelar de Phoenix se manifiesta en su estilo de combate al incendiar el campo de batalla con sus granadas aturdidoras y cegadoras. Sin importar si cuenta con apoyo o no, participará en la batalla bajo sus propios términos.","it-IT":"Originario del Regno Unito, Phoenix brilla per il suo stile di combattimento, che infiamma il campo di battaglia come un lampo abbagliante. Con o senza rinforzi, è sempre pronto a gettarsi nella mischia secondo le sue regole.","ar-AE":"تظهر قوة النجم التي يتمتع بها فينيكس القادم من المملكة المتحدة جلية في أسلوبه القتالي، حيث يشعل ميدان القتال بتألقه ووميضه. وسواء كانت لديه رفقة أم لا فهو يندفع نحو القتال دائمًا دون انتظار أحد.","es-ES":"Phoenix proviene del Reino Unido y sus poderes estelares salen a relucir con su estilo de combate, que prende fuego al campo de batalla de forma deslumbrante. Con apoyo o en solitario, él es quien decide cuándo y cómo se lucha.","en-US":"Hailing from the U.K., Phoenix''s star power shines through in his fighting style, igniting the battlefield with flash and flare. Whether he''s got backup or not, he''s rushing in to fight on his own terms.","de-DE":"Phoenix stammt aus Großbritannien und seine Starqualitäten kommen auch in seinen Kampffähigkeiten zur Geltung. Ob mit oder ohne Verstärkung - der Kampf beginnt, wenn er es sagt.","ja-JP":"イギリスからやってきたスター、フェニックスの力は、彼自身の戦闘スタイルによってさらに輝きを増し、戦場を閃光と火炎で燃え上がらせる。彼は援護の有無など気にもせず、単身で戦闘の只中に飛び込んでいくのだ。","ko-KR":"영국 출신 피닉스의 탁월한 능력은 전장을 섬광탄과 불꽃으로 수놓는 전투 스타일에서 비롯됩니다. 팀의 지원이 있든 없든 피닉스는 자신만의 방식으로 전투를 이끌어갑니다.","fr-FR":"En provenance du Royaume-Uni, Phoenix illumine le champ de bataille avec ses pouvoirs astraux et son style de combat flamboyant. Peu importe que les renforts arrivent ou non, il fonce au combat quand il le décide.","id-ID":"Berasal dari Britania Raya, kilau daya tarik Phoenix terlihat dalam gaya bertarungnya, menyulut battlefield dengan kilat dan api. Saat sendiri maupun dibantu rekannya, dia akan memasuki pertarungan sesuka hatinya.","pl-PL":"Wywodzący się z Wielkiej Brytanii Phoenix bryluje na polu walki za sprawą swych popisowych mocy, rozjaśniając okolicę błyskiem i stylem. Z towarzyszami lub bez, zawsze rwie się do starcia na własnych zasadach.","pt-BR":"Chegando com tudo diretamente do Reino Unido, o poder estelar de Phoenix reluz em seu estilo de luta, incendiando o campo de batalha com luz e estilo. Tendo ajuda ou não, ele entra na luta como e quando achar que deve.","th-TH":"Phoenix ผู้มีชื่อเสียงเลื่องลือแห่งสหราชอาณาจักร พลังของเขาลุกโชติช่วงด้วยสไตล์การต่อสู้ ซึ่งเผาไหม้สนามรบให้เป็นจุณด้วยแสงสว่างและเปลวไฟ ไม่ว่าจะมีทีมคอยสนับสนุนหรือไม่ \nเขาก็จะพุ่งสู่สงครามด้วยความตั้งใจของตนเองเสมอ","ru-RU":"Представитель Великобритании Phoenix демонстрирует звездную силу во всех аспектах своего боевого стиля: он сражается красиво и ярко, всегда навязывает противнику свои условия и отважно устремляется в бой даже без поддержки.","tr-TR":"Aramıza Birleşik Krallık''tan katılan ve yıldızlardan aldığı gücü dövüş stilinin her noktasına yansıtan Phoenix, savaş alanını alevlerle ve patlamalarla aydınlatır. Arkasında destek olsun olmasın, bildiği gibi savaşmak için ileri atılacağından şüpheniz olmasın.","vi-VN":"Xuất thân từ nước Anh đầy mưa gió, sức mạnh của Phoenix nằm ở lối chiến đấu của hắn, với khả năng thiêu đốt cả chiến trường bằng hỏa mù chói lóa. Phoenix luôn tỏa sáng dù là phối hợp tác chiến cùng đồng đội hay chiến đấu độc lập.","zh-CN":"来自不列颠群岛的“不死鸟”举手投足中无处不洋溢着大牌明星风范，他就像一团耀眼的烈焰，动辄燃遍全场。对他来说，有没有后援不重要，冲锋陷阵时的派头更重要。","zh-TW":"菲尼克斯來自英國，他的星辰之力融會於其戰鬥風格中，發出的烈焰足以讓星火燎原。不管有沒有後援，他都能衝鋒陷陣，獨自撂倒敵人。"}'::jsonb, 'Phoenix', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/displayicon.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/displayicon.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/killfeedportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/minimapportrait.png', null, 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/background.png', array['74321cff', '0f1923ff', '262423ff', '0f192300'], true, true, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, '{"es-MX":"Veto","it-IT":"Veto","ar-AE":"فيتو","es-ES":"Veto","en-US":"Veto","de-DE":"Veto","ja-JP":"ヴィトー","ko-KR":"비토","fr-FR":"Veto","id-ID":"Veto","pl-PL":"Veto","pt-BR":"Veto","th-TH":"Veto","ru-RU":"Veto","tr-TR":"VETO","vi-VN":"Veto","zh-CN":"禁灭","zh-TW":"維托"}'::jsonb, '{"es-MX":"Veto es un vigilante originario de Senegal que, con la ayuda de una mutación genética, desafía las reglas del combate al anular los poderes y la tecnología de sus oponentes. En el campo de batalla de Veto, las armas son tu única garantía.","it-IT":"Potenziato da un''inarrestabile mutazione genetica, il vigilante senegalese Veto infrange ogni regola d''ingaggio annullando i poteri e la tecnologia degli avversari. Quando Veto è in battaglia, le armi sono l''unica certezza.","ar-AE":"مع تعزيزه بطفرته الجينية الفائقة، يتحدى الشرطي السنغالي فيتو قواعد الاشتباك عبر إبطال مفعول قدرات خصومه وتقنياتهم. في معارك فيتو، مهاراتك في استخدام الأسلحة هي الضمان الوحيد للنجاة.","es-ES":"Veto, un asesino a sueldo senegalés cuya fuerza radica en una potente mutación genética, pone en jaque el funcionamiento de las iniciaciones anulando tanto las capacidades como la tecnología de su oponente. Cuando juegas en el campo de Veto, las armas de fuego son el mejor aliado.","en-US":"Empowered by an unstoppable DNA mutation, Senegalese enforcer Veto defies the rules of engagement by nullifying his opponent''s powers and technology. On Veto''s battlefield, gunplay is your only guarantee.","de-DE":"Seine unglaublichen DNA-Mutationen versetzen den senegalesischen Vollstrecker Veto in die Lage, alle Kräfte und Technologien seiner Gegner zu neutralisieren und so die Situation auf dem Schlachtfeld grundlegend umzuwälzen. Auf Vetos Schlachtfeld kannst du dich nur auf deine Waffe verlassen.","ja-JP":"セネガル出身のヴィトーは制御不能なDNA変異によって力を得た武闘派の精鋭だ。敵のパワーとテクノロジーを無効化し、戦いのルールを塗り替える。戦場にヴィトーがいるなら、確実なのは銃撃だけだ。","ko-KR":"멈출 수 없는 DNA 변이로 강화된 세네갈 출신 집행자 비토는 상대의 능력과 기술을 무력화함으로써 교전 수칙을 무시합니다. 비토의 전장에서 믿을 건 사격 실력뿐입니다.","fr-FR":"Alimenté par une mutation génétique imparable, Veto, l''homme de main sénégalais, défie les règles du combat en neutralisant les pouvoirs et la technologie de ses adversaires. La seule chose que vous trouverez avec Veto sur le champ de bataille, c''est des armes.","id-ID":"Diperkuat mutasi DNA yang tak terbendung, enforcer asal Senegal Veto menabrak aturan tempur dengan melumpuhkan kekuatan dan teknologi lawannya. Di medan tempur Veto, tembakan adalah satu-satunya peganganmu.","pl-PL":"Senegalski stróż prawa Veto, wzmocniony przez niepohamowaną mutację DNA, tworzy własne zasady walki, przeciwdziałając mocom i technologii przeciwnika. Gdy mu się sprzeciwiasz, możesz ufać wyłącznie swojej broni palnej.","pt-BR":"Portador de uma mutação genética avassaladora, o implacável Agente senegalês Veto desafia as regras do combate, anulando os poderes e as tecnologias de seus oponentes. No campo de batalha do Veto, a troca de tiros é sua melhor opção.","th-TH":"Veto ผู้รักษากฎหมายชาวเซเนกัลที่ได้รับพลังจากการกลายพันธุ์ของ DNA ที่ไม่อาจหยุดยั้งได้ แหกกฎการต่อสู้ด้วยการทำให้พลังและเทคโนโลยีของคู่ต่อสู้ไร้ผล ในสนามรบของ Veto มีแต่ปืนเท่านั้นที่จะช่วยคุณได้","ru-RU":"Veto, заступник из Сенегала, усилен мощной мутацией ДНК. Он меняет правила ведения боя, нейтрализуя силы и технику врага. Сражаясь с Veto, можно полагаться только на оружие.","tr-TR":"Durdurulamaz bir DNA mutasyonuyla gücüne güç katan Senegalli fedai Veto, rakibinin güçlerini ve teknolojisini etkisiz kılarak çatışma kurallarını hiçe sayıyor. Veto''nun savaş meydanında tek güvenilir seçeneğin silahların.","vi-VN":"Được cường hóa bởi đột biến gien bất khả kháng cự, Veto - người thi hành luật đến từ Senegal - thách thức mọi quy tắc chiến đấu bằng cách vô hiệu hóa toàn bộ sức mạnh và công nghệ của đối thủ. Trên chiến trường của Veto, kỹ năng bắn súng là thứ duy nhất giúp bạn toàn mạng.","zh-CN":"来自西非的“禁灭”是一名压制型英雄，因基因突变获得了超凡力量。禁灭打破了既有的战斗规则，无论敌人使出怎样的手段和科技，在他面前都形同虚设。禁灭出现在战场上时，只有枪法才是你唯一的保障。","zh-TW":"維托是來自塞內加爾的執法者，身上帶有無可遏抑的DNA突變，也因此獲得能力強化。他能使對手的能力和科技武器變成毫無作用，完全視戰鬥規則為無物。與維托交戰時，槍法是你唯一的依靠。"}'::jsonb, 'Pine', '2025-10-07T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/displayicon.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/displayicon.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/killfeedportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/minimapportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/background.png', array['1a5d65ff', '0f1923ff', '0f1923ff', '1a5d65ff'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, '{"es-MX":"Astra","it-IT":"Astra","ar-AE":"أسترا","es-ES":"Astra","en-US":"Astra","de-DE":"Astra","ja-JP":"アストラ","ko-KR":"아스트라","fr-FR":"Astra","id-ID":"Astra","pl-PL":"Astra","pt-BR":"Astra","th-TH":"Astra","ru-RU":"Astra","tr-TR":"ASTRA","vi-VN":"Astra","zh-CN":"星礈","zh-TW":"亞星卓"}'::jsonb, '{"es-MX":"La agente ghanesa Astra canaliza las energías del cosmos para remodelar los campos de batalla a su antojo. Con pleno dominio de su forma astral y un talento para una profunda previsión estratégica, siempre está eones por delante del próximo movimiento de su enemigo.","it-IT":"Astra, la viaggiatrice astrale ghanese, sfrutta le energie del cosmo per plasmare a piacimento il campo di battaglia. Grazie alla completa padronanza della sua forma astrale e a una lungimiranza strategica quasi soprannaturale, è sempre eoni avanti rispetto alla prossima mossa del nemico.","ar-AE":"تسخّر العميلة الغانية أسترا الطاقات الكونية لإعادة تشكيل معالم ميادين القتال وفقًا لرغباتها الشخصية. ومع تحكمها الكامل بهيئتها الفضائية، وموهبتها في الرؤية الاستراتيجية المعمقة، تسبق خطوة خصومها التالية على الدوام بسنوات ضوئية.","es-ES":"Astra, la agente ghanesa, controla las energías del cosmos para dar forma al campo de batalla a su antojo. Con pleno dominio de su forma astral y un gran talento para la anticipación estratégica, siempre va eones por delante de los movimientos de sus enemigos.","en-US":"Ghanaian Agent Astra harnesses the energies of the cosmos to reshape battlefields to her whim. With full command of her astral form and a talent for deep strategic foresight, she''s always eons ahead of her enemy''s next move.","de-DE":"Die ghanaische Agentin Astra nutzt die Energien des Kosmos, um das Schlachtfeld nach ihren Vorlieben zu verändern. Durch ihre Astralform und ihr Talent für strategische Weitsicht ist sie dem nächsten Zug ihrer Gegner immer Äonen voraus.","ja-JP":"ガーナ人エージェントのアストラは、宇宙のエネルギーを駆使して戦場を思いのままに作り変える。アストラルフォームを自在に操り、戦略的な先見性を備えた彼女は、敵のはるか先を行くことができる。","ko-KR":"가나 출신 요원 아스트라는 우주의 힘을 활용해 자신의 마음에 따라 전장의 모습을 바꿉니다. 천상계 형상을 자유자재로 이용하고 심도 있게 전략을 예측해 언제나 적보다 몇 수 앞서 움직입니다.","fr-FR":"L''agent ghanéen Astra canalise les énergies du cosmos pour façonner le champ de bataille à sa convenance. Avec une maîtrise complète de sa forme astrale et un talent pour la planification stratégique, elle a toujours une large avance sur ses ennemis.","id-ID":"Agen asal Ghana, Astra, memberdayakan kekuatan semesta untuk mereka ulang battlefield sesuka hatinya. Dengan kendali penuh atas wujud astralnya dan bakat meramal strategisnya, dia akan selalu unggul dari musuhnya.","pl-PL":"Ghańska agentka Astra ujarzmia kosmiczne energie, by przeobrazić pola bitwy według własnego widzimisię. Dzięki temu, że w pełni panuje nad swoją astralną formą i ma niezwykły talent do przewidywania strategicznych posunięć, zawsze wyprzedza o całe eony kolejne działania wroga.","pt-BR":"Astra, a Agente ganense, utiliza energias cósmicas para moldar o campo de batalha a seu bel-prazer. Com total domínio da sua forma astral e um talento estratégico nato, ela está sempre anos-luz à frente dos inimigos.","th-TH":"Astra เอเจนท์ชาวกานาผู้ควบคุมพลังแห่งจักรวาลเพื่อปรับรูปแบบสนามรบให้เป็นไปตามความต้องการของเธอ ด้วยความสามารถในการควบคุมร่างดวงดาวและพรสวรรค์ในการวางแผนกลยุทธ์อย่างลึกซึ้งของเธอ เธอมักจะนำหน้าศัตรูอยู่หนึ่งก้าวเสมอ","ru-RU":"Astra, агент из Ганы, управляет пространством и временем и способна изменять поле битвы. Полный контроль над астральной формой и талант стратегического предвидения позволяют ей опережать врага на целую вечность.","tr-TR":"Ganalı ajan Astra, kozmosun enerjisini kullanarak savaş meydanını lehine değiştirebiliyor. Astral yolculuğu üzerinde tam kontrole sahip olması ve engin stratejik öngörüsüyle, düşmanın bir sonraki hamlesinden her zaman birkaç ışık yılı önde.","vi-VN":"Astra là một đặc vụ tới từ Ghana, cô sử dụng năng lượng của vũ trụ để định hình trận chiến theo ý muốn của bản thân. Với khả năng điều khiển thể tinh vân và tài năng chiến thuật bao quát, cô ấy luôn đi trước đối thủ của mình 10 bước.","zh-CN":"来自非洲大陆的“星礈”可以操控宇宙能量来重塑战场。她可以进入星界形态，以超脱凡界的战略眼光洞悉战场，抢在敌人行动之前便占得先机。","zh-TW":"亞星卓來自非洲迦納，她能駕馭宇宙之力，「隨星所欲」重塑戰場形勢。她完全掌控了星體型態的力量，且擁有洞見觀瞻的戰略能力，因此總是能遙遙領先對手。"}'::jsonb, 'Rift', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/displayicon.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/displayicon.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/killfeedportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/minimapportrait.png', null, 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/background.png', array['26146cff', '0f1923ff', '5210c6ff', '0f192300'], true, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, '{"es-MX":"Brimstone","it-IT":"Brimstone","ar-AE":"بريمستون","es-ES":"Brimstone","en-US":"Brimstone","de-DE":"Brimstone","ja-JP":"ブリムストーン","ko-KR":"브림스톤","fr-FR":"Brimstone","id-ID":"Brimstone","pl-PL":"Brimstone","pt-BR":"Brimstone","th-TH":"Brimstone","ru-RU":"Brimstone","tr-TR":"BRIMSTONE","vi-VN":"Brimstone","zh-CN":"炼狱","zh-TW":"布史東"}'::jsonb, '{"es-MX":"Proveniente de EE.UU., el arsenal orbital de Brimstone asegura una ventaja constante para su equipo. Su habilidad de proporcionar información de forma precisa y segura lo hace un comandante sin igual en el campo.","it-IT":"L''arsenale orbitale dello statunitense Brimstone fa in modo che la sua squadra abbia sempre un vantaggio. La sua capacità di fornire utilità con precisione e sicurezza lo rende un comandante pragmatico e impareggiabile.","ar-AE":"مع انضمامه من الولايات المتحدة الأمريكية، يمتلك بريمستون ترسانة مدارية تضمن امتلاك فريقه الأفضلية على الدوام. وتتكفل قدرته على إيصال معدات دعمه بدقة وأمان في جعله القائد الميداني الذي لا يوجد نظير له.","es-ES":"De origen estadounidense, Brimstone cuenta con un arsenal de órbita que garantiza que su equipo siempre vaya por delante. Su capacidad para aportar herramientas de utilidad de una forma segura y precisa lo convierte en un comandante de primera línea sin igual.","en-US":"Joining from the U.S.A., Brimstone''s orbital arsenal ensures his squad always has the advantage. His ability to deliver utility precisely and safely make him the unmatched boots-on-the-ground commander.","de-DE":"Brimstone kommt aus den USA und sein orbitales Arsenal sorgt dafür, dass sein Team stets einen klaren Vorteil hat. Er sorgt präzise und sicher für Unterstützung, was ihn zu einem perfekten Kommandanten macht.","ja-JP":"アメリカ合衆国から参戦したブリムストーンの衛星軌道兵器があれば、部隊は常に優位に立つことができる。離れた場所から確実に支援を送るアビリティーを持つ彼は、現地での指揮にうってつけの存在なのだ。","ko-KR":"미국 출신 브림스톤은 궤도 무기를 활용해 아군에게 유리하도록 전투를 이끕니다. 안전하고 정확하게 다양한 수단으로 팀을 보조하는 능력 덕분에 그는 최고의 야전 사령관으로 불립니다.","fr-FR":"Tout droit venu des États-Unis d''Amérique, Brimstone possède un arsenal orbital qui permet à son escouade de toujours avoir l''avantage. La précision et la fiabilité de ses compétences utilitaires font de lui un commandant sans égal sur le terrain.","id-ID":"Bergabung dari AS, persenjataan orbital Brimstone memastikan squad-nya selalu di posisi menguntungkan. Kemampuannya dalam mendaratkan bantuan secara presisi dan aman menjadikannya seorang komandan tempur tidak tertandingi.","pl-PL":"Orbitalny arsenał pochodzącego z USA Brimstone’a zawsze zapewnia jego zespołowi przewagę. Jego zdolność zapewnienia precyzyjnego i bezpiecznego wsparcia czyni go niezrównanym dowódcą w samym sercu akcji.","pt-BR":"Vindo diretamente dos EUA, o arsenal orbital do Brimstone garante que o esquadrão dele sempre esteja em vantagem. Sua capacidade de oferecer utilitários com precisão e segurança faz dele um comandante inigualável na linha de frente.","th-TH":"Brimstone เข้าร่วมจากสหรัฐอเมริกา การโจมตีด้วย Orbital Arsenal ของเขาจะช่วยให้ทีมได้เปรียบเสมอ ความสามารถในการสนับสนุนอย่างแม่นยำจากระยะไกลทำให้เขาเป็นผู้บัญชาการภาคพื้นดินที่ไม่มีใครเทียบได้","ru-RU":"Уроженец США Brimstone обеспечивает своей команде преимущество перед противником благодаря орбитальной технике. Возможность удаленно оказывать помощь там, где это требуется, делает его несравненным боевым командиром.","tr-TR":"Aramıza ABD''den katılan Brimstone''un hava araçları sayesinde takımı her zaman 1-0 öndedir. Gereken her türlü işlevselliği titizlikle ve güvenle sağlaması, muharebe alanında bu kumandanı eşsiz kılar.","vi-VN":"Đến từ Hợp chủng quốc Hoa Kỳ, Brimstone luôn đảm bảo lợi thế cho đồng đội bằng những vũ khí tối tân ngoài quỹ đạo của mình. Những chiêu thức mang lại khả năng hỗ trợ chính xác và đảm bảo an toàn khiến Brimstone xứng đáng là một sĩ quan lục quân vô địch.","zh-CN":"“炼狱”来自美洲大陆，他能使用各种轨道武器来为团队提供精确支援和创造战术优势，是前线指挥官的不二人选。  ","zh-TW":"來自美國的布史東擁有強大的衛星武器，讓他的隊伍永遠處於優勢。他能投放戰略工具支援前線，包準「恰到好處」且萬無一失，讓他成為地表最強指揮官。"}'::jsonb, 'Sarge', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/displayicon.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/displayicon.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/killfeedportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/minimapportrait.png', null, 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/background.png', array['363c4fff', '0f1923ff', '211d21ff', '0f192300'], false, true, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, '{"es-MX":"Iso","it-IT":"Iso","ar-AE":"آيسو","es-ES":"Iso","en-US":"Iso","de-DE":"Iso","ja-JP":"アイソ","ko-KR":"아이소","fr-FR":"Iso","id-ID":"Iso","pl-PL":"Iso","pt-BR":"Iso","th-TH":"Iso","ru-RU":"Iso","tr-TR":"ISO","vi-VN":"Iso","zh-CN":"壹决","zh-TW":"離索"}'::jsonb, '{"es-MX":"El agente chino Iso es un neutralizador a sueldo que entra en estado de fluidez para desmantelar a sus oponentes. Reconfigura la energía ambiental para convertirla en una protección a prueba de balas y avanza con determinación hacia su próximo duelo a muerte.","it-IT":"Iso, il risolutore su commissione cinese, entra in uno stato di concentrazione elevata per distruggere i nemici. Trasformando l''energia ambientale in una protezione antiproiettile, si lancia sicuro nel suo prossimo duello all''ultimo sangue.","ar-AE":"يدخل اختصاصي المهام الصعبة المأجور الصيني آيسو في حالة تركيز خاص لتقويض أركان الخصوم. ومن خلال تحويل الطاقة المحيطة إلى حماية مضادة للرصاص، يتقدم بتركيز ليخوض مبارزته التالية حتى الموت.","es-ES":"Iso, el asesino a sueldo chino, entra en un estado de flujo de energía para acabar con sus rivales. Capaz de reconfigurar la energía del ambiente para crear una protección a prueba de balas, avanza concentrado hacia su siguiente duelo a muerte.","en-US":"Chinese fixer for hire Iso falls into a flow state to dismantle the opposition. Reconfiguring ambient energy into bulletproof protection, he advances with focus towards his next duel to the death.","de-DE":"Der chinesische Problemlöser Iso kommt in einen Flow und nimmt so seine Gegner auseinander. Er wandelt Umgebungsenergie in kugelsichere Panzerung um und sucht zielstrebig nach seinem nächsten Duell auf Leben und Tod.","ja-JP":"中国出身の雇われフィクサーであるアイソは、フロー状態に入って敵の勢力を解体する。彼は周囲のエネルギーを防弾の守りとして再構築しながら、命を懸けた次の決闘へと向かう。","ko-KR":"중국 출신인 청부 해결사 아이소는 집중 상태에 들어가 적을 와해시킵니다. 아이소는 주변 에너지를 방탄 보호막으로 재구성해 전진하며 쓰러질 때까지 다음 결투 상대에게 집중합니다.","fr-FR":"Venu de Chine et spécialiste de missions délicates, Iso se fond dans le flux de radianite pour démanteler les réseaux ennemis. Capable de restructurer l''énergie ambiante en protection pare-balles, rien ne l''arrêtera sur le chemin de son prochain duel à mort.","id-ID":"Eksekutor bayaran terpercaya asal Cina, Iso, memasuki kondisi fokus untuk memberantas lawan. Dengan merombak energi sekitar menjadi proteksi antipeluru, dia fokus maju ke duel selanjutnya hingga titik darah penghabisan.","pl-PL":"Iso, chiński macher na zlecenie, wchodzi w stan skupienia, aby łamać wszelki opór. Przekształcając energię otoczenia w kuloodporną osłonę, naciera w skupieniu w kierunku następnego pojedynku na śmierć i życie.","pt-BR":"Iso é um mercenário chinês que entra em estado de fluxo para desmantelar os oponentes. Ele reconfigura a energia do ambiente para se proteger de balas e avança totalmente focado em direção ao próximo duelo até a morte.","th-TH":"มือปืนรับจ้างชาวจีน Iso จะเข้าสู่สภาวะจดจ่อเพื่อทำลายล้างคู่ต่อสู้ ด้วยเทคโนโลยีการเปลี่ยนแปลงพลังงาน Radianite ในสภาพแวดล้อมให้กลายเป็นเกราะป้องกันกระสุน เขาทะยานสู่การดวลครั้งต่อไปอย่างมุ่งมั่น","ru-RU":"Китайский агент Iso – опытный боец, способный устранить любую цель. Он преобразовывает окружающую энергию в пуленепробиваемые щиты и уверенно вступает в отчаянные бои один на один.","tr-TR":"Çinli kiralık suikastçı Iso düşmanların saflarını darmadağın etmek için bir akış haline girer. Çevredeki enerjiyi yeniden şekillendirerek kurşun geçirmez bir kalkana dönüştüren Iso odağını yitirmeden bir sonraki ölümüne düellosuna ilerler.","vi-VN":"\"Lính đánh thuê\" người Trung Quốc, Iso rơi vào trạng thái dòng chảy để triệt tiêu đối thủ. Anh tái định hình cấu trúc năng lượng xung quanh thành một lớp bảo vệ chống đạn và vận sức tập trung vào trận đấu tay đôi tiếp theo cho đến khi có người ngã xuống.","zh-CN":"“壹决”是华夏文明的后裔。他是枪斗的艺术家，战斗时仿佛沉浸在自我的心流中，将对手的抵抗悉数瓦解。他还能重构环境中的能量来阻挡子弹。战斗中的他时刻保持专注，并渴望与强敌一决高下。","zh-TW":"中國傭兵離索進入殺戮心流狀態，重組周圍環境的能量化作防彈護盾，專心致志地邁向下一次生死對決。"}'::jsonb, 'Sequoia', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/displayicon.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/displayicon.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/killfeedportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/minimapportrait.png', null, 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/background.png', array['30336eff', '0f1923ff', '20155dff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, '{"es-MX":"Clove","it-IT":"Clove","ar-AE":"كلوف","es-ES":"Clove","en-US":"Clove","de-DE":"Clove","ja-JP":"クローヴ","ko-KR":"클로브","fr-FR":"Clove","id-ID":"Clove","pl-PL":"Clove","pt-BR":"Clove","th-TH":"Clove","ru-RU":"Clove","tr-TR":"CLOVE","vi-VN":"Clove","zh-CN":"暮蝶","zh-TW":"珂樂芙"}'::jsonb, '{"es-MX":"Clove llega desde Escocia buscando pleito, y sus travesuras no paran ni en el calor de la batalla, ni en el frío de la muerte. Le joven inmortal confunde a los enemigos incluso desde el más allá, porque saben que en cualquier momento puede regresar al mundo de los vivos.","it-IT":"L''agente scozzese combinaguai Clove crea scompiglio tra i nemici tanto nel fuoco della battaglia quanto nel gelo della morte. Quest''immortale tiene i nemici sulle spine anche dall''oltretomba, dalla quale può fare ritorno in ogni momento.","ar-AE":"تُلحق كلوف الاسكتلندية المشاكسة الأذى بالأعداء سواء فى حرارة القتال أو برودة الموت. وتُبقي المخلوقة الأزلية الشابة الأعداء في حيرة من أمرهم حتى عند موتها الذي لا يطول سوى برهة في المعتاد.","es-ES":"Le agente escocese Clove no para de liarla, tanto en el fragor de la batalla como en el frío abrazo de la muerte. Le joven inmortal trae de cabeza a sus enemigos incluso desde el más allá, porque saben que en cualquier momento podría volver al mundo de los vivos.","en-US":"Scottish troublemaker Clove makes mischief for enemies in both the heat of combat and the cold of death. The young immortal keeps foes guessing, even from beyond the grave, their return to the living only ever a moment away.","de-DE":"Clove aus Schottland ist gut darin, Gegner sowohl in der Hitze des Gefechts als auch angesichts der Kälte des Todes auf Trab zu halten. Clove ist unsterblich und kann selbst aus dem Grab heraus viel Unheil stiften und Gegner im Unklaren über die nächsten Schritte lassen.","ja-JP":"スコットランド出身のトラブルメーカー「クローヴ」は、激しい戦闘の最中も、冷たい死を迎えたときすらも敵に悪戯を仕掛ける。若き不死の存在であるクローヴは、死の向こう側からでさえ敵に疑念を抱かせ翻弄する。生ける世界への帰還はいつもほんの一瞬のことだから。","ko-KR":"스코틀랜드 출신 말썽꾸러기 클로브는 전투의 열기 속에서도, 싸늘한 죽음 속에서도 적을 괴롭힙니다. 젊은 불멸자인 클로브는 죽은 후에도 적에게 곧 살아 돌아올 거라는 불안감을 안겨 줍니다.","fr-FR":"Clove, l''intenable Écossais·e, déstabilise l''ennemi dans le feu de l''action comme le froid de la mort. Iel sème le trouble dans les rangs ennemis, même depuis sa tombe, car sa mort ne dure jamais très longtemps.","id-ID":"Pembuat onar dari Skotlandia, Clove, membawa masalah bagi musuh di tengah panasnya pertempuran dan dinginnya kematian. Manusia abadi ini membuat musuhnya bertanya-tanya, bahkan soal kebangkitan setelah mati. Kembalinya dia ke dunia hanya tinggal menunggu waktu.","pl-PL":"Szkocku łobuzu Clove płata figle wrogom zarówno w ogniu walki, jak i w zimnych objęciach śmierci. Młodu nieśmiertelnu trzyma przeciwników w niepewności nawet zza grobu. Wróg nigdy nie wie, kiedy Clove wróci do świata żywych.","pt-BR":"Clove, ume encrenqueire da Escócia, vai desorientar os inimigos tanto no calor do combate quanto no frio da morte. Jovem e imortal, elu mantém os inimigos confusos até do além-túmulo: momentos após a morte, elu retorna à vida.","th-TH":"Clove จอมก่อปัญหาชาวสก็อต จะสร้างความโกลาหลให้กับเหล่าศัตรูทั้งในระหว่างการต่อสู้\nอันดุเดือดและในยามที่หมดลมหายใจ เด็กอมตะ\nผู้นี้จะทำให้เหล่าศัตรูต้องคอยคาดเดา\nแม้ในโลกหลังความตาย เขาจะกลับมามีชีวิต\nหลังจากที่เวลาผ่านไปแค่ครู่เดียว","ru-RU":"Clove, родом из Шотландии, умеет навредить противникам и в пылу боя, и во хладе смерти. Врагам остается только гадать, когда же агент восстанет из могилы, – а это может случиться в любой момент.","tr-TR":"İskoç ajan Clove muziplikleriyle hem çatışma sırasında hem de ölümden sonra sürekli ortalığı karıştırıyor. Ölüm nedir bilmeyen bu genç ajanın mezarından çıkıp gelerek düşmanlarının başına bela olması daima an meselesi.","vi-VN":"Chuyên gia gây rối đến từ Scotland, Clove \"quậy đục nước\" kẻ địch ngay giữa chiến trường nóng bỏng và cả trước cái chết lạnh lẽo. Kẻ bất tử trẻ tuổi luôn khiến kẻ địch phải đau đầu, kể cả khi đã bị vùi sâu xuống lòng đất, cậu ấy vẫn có thể tái sinh chỉ sau chốc lát.","zh-CN":"来自不列颠群岛北部的“暮蝶”擅长用自己的招牌恶作剧来捉弄敌人。即便在被击败后，这位年轻的永生者也能继续干扰敌人，甚至出其不意地返场再战。","zh-TW":"蘇格蘭裔搗蛋鬼珂樂芙遊走於戰鬥的激情和死亡的冷酷之間，總讓敵人捉摸不定。這位永生不朽的年輕人最愛將敵人耍得團團轉，即便身中數槍倒下，也可能隨時復活、就像沒事一樣。"}'::jsonb, 'Smonk', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/displayicon.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/displayicon.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/killfeedportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/minimapportrait.png', null, 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/background.png', array['4b1d80ff', '0f1923ff', 'c347c7ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, '{"es-MX":"Neon","it-IT":"Neon","ar-AE":"نيون","es-ES":"Neon","en-US":"Neon","de-DE":"Neon","ja-JP":"ネオン","ko-KR":"네온","fr-FR":"Neon","id-ID":"Neon","pl-PL":"Neon","pt-BR":"Neon","th-TH":"NEON","ru-RU":"Neon","tr-TR":"NEON","vi-VN":"Neon","zh-CN":"霓虹","zh-TW":"妮虹"}'::jsonb, '{"es-MX":"La agente filipina Neon avanza a velocidades impactantes, descargando ráfagas de energía bioeléctrica tan rápido como su cuerpo la genera. Se adelanta velozmente a sus enemigos para atraparlos desprevenidos y luego los fulmina más rápido que un rayo.","it-IT":"Neon, la scheggia delle Filippine, scatta a velocità supersoniche, emettendo scariche di bioelettricità generate dal suo corpo. Questo agente coglie i nemici di sorpresa con la sua rapidità e poi li colpisce più veloce di un fulmine.","ar-AE":"تندفع العميلة الفلبينية نيون إلى الأمام بسرعة مذهلة، وتفرغ دفقات من أشعة الكهرباء الحيوية بسرعة توليد جسمها لها. وتسبق الجميع للإيقاع بالأعداء في غفلة من أمرهم، ثم تضربهم بسرعة تفوق سرعة البرق.","es-ES":"Neon, una agente filipina, se lanza hacia la batalla a una velocidad trepidante, disparando descargas bioeléctricas tan rápido como las genera su cuerpo. Se adelanta para pillar a sus enemigos desprevenidos y acabar con ellos más rápida que el rayo.","en-US":"Filipino Agent Neon surges forward at shocking speeds, discharging bursts of bioelectric radiance as fast as her body generates it. She races ahead to catch enemies off guard then strikes them down quicker than lightning.","de-DE":"Die philippinische Agentin Neon prescht blitzschnell nach vorn und entlädt Blitze aus bioelektrischer Strahlung, die ihr Körper mit einer ebensolchen Geschwindigkeit erzeugt. Sie stürmt vorwärts, um unvorbereitete Gegner zu überraschen und erledigt sie dann mit Lichtgeschwindigkeit.","ja-JP":"フィリピン出身のエージェント、ネオンは驚異的なスピードで戦場を突き進み、生体電気を生み出して激しい電撃を解き放つ。彼女はそのスピードで敵の不意をつき、稲妻よりも速く相手を打ち倒す。","ko-KR":"필리핀 출신 요원 네온은 엄청난 속도로 달리며 몸에서 만들어낸 생체 전기를 빠르게 방출시킵니다. 네온은 빠르게 움직여 방심한 적을 기습하고, 번개보다 빠르게 제압합니다.","fr-FR":"Originaire des Philippines, Neon traverse le champ de bataille à une vitesse fulgurante, libérant de grosses décharges de radiance bioélectrique générées par son corps. Elle contourne les ennemis pour les prendre par surprise et les éliminer en un éclair.","id-ID":"Agen dari Filipina, Neon, melesat maju dengan kecepatan yang mencengangkan, menyemburkan pancaran bioelektrik secepat tubuhnya menghasilkannya. Dia berlari untuk mengejutkan musuh, lalu menyerang mereka lebih cepat dari kilat.","pl-PL":"Filipińska agentka Neon z niebotyczną prędkością pędzi naprzód, emitując impulsy bioelektrycznego blasku równie szybko, jak jej ciało je wytwarza. Mknie niczym wiatr, aby wziąć wrogów z zaskoczenia, po czym wykańcza ich szybciej niż błyskawica.","pt-BR":"Neon, nossa Agente filipina, avança em velocidades incríveis, descarregando surtos de radiância bioelétrica tão rapidamente quanto seu corpo consegue gerá-los. Ela corre à frente para pegar os inimigos de surpresa, abatendo-os mais rápido do que um raio.","th-TH":"Neon เอเจนท์ชาวฟิลิปปินส์พุ่งไปข้างหน้าด้วยความเร็วที่น่าทึ่ง พร้อมปลดปล่อยระลอกไฟฟ้าชีวภาพได้เร็วพอ ๆ กับที่ร่างกายของเธอสร้างได้ เธอเคลื่อนที่อย่างรวดเร็วเพื่อจัดการศัตรูอย่างรวดเร็วแบบไม่ทันได้ตั้งตัว","ru-RU":"Филиппинка Neon способна невероятно быстро передвигаться благодаря биоэлектрическим импульсам, которые генерирует ее тело. Это позволяет ей заставать врагов врасплох и расправляться с ними быстрее молнии.","tr-TR":"Filipinli Ajan Neon, şoke edici bir hızla öne atılır ve bedeninin ürettiği biyoelektrik dalgalarını düşmanların üstüne salar. Düşmanları gafil avlamak için yarışırcasına koşar ve hepsini yıldırım hızıyla indirir.","vi-VN":"Neon, một Đặc Vụ người Phillipines với kỹ năng phóng về phía trước với tốc độ chóng mặt, bắn ra các chùm bức xạ điện sinh học nhanh như chính cách cơ thể cô ấy tạo ra nó. Cô luôn xông lên trước để tìm kẻ thù khi chúng chưa kịp trở tay, để rồi hạ gục chúng trong chớp mắt.","zh-CN":"来自西太平洋群岛的“霓虹”拥有惊人的速度，可以在运动中产生和释放生物电能量。她擅长利用快速机动，以闪电般的效率把敌人打得措手不及。","zh-TW":"妮虹是來自菲律賓的特務，她的身體能產生帶有輻能的生物電流，讓她能一邊高速衝刺一邊釋放電擊。她擅長趁虛而入，然後以迅雷不及掩耳的速度擊倒敵人。"}'::jsonb, 'Sprinter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/displayicon.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/displayicon.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/killfeedportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/minimapportrait.png', null, 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/background.png', array['413476ff', '0f1923ff', '38328eff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('7f94d92c-4234-0a36-9646-3a87eb8b5c89'::uuid, '{"es-MX":"Yoru","it-IT":"Yoru","ar-AE":"يورو","es-ES":"Yoru","en-US":"Yoru","de-DE":"Yoru","ja-JP":"ヨル","ko-KR":"요루","fr-FR":"Yoru","id-ID":"Yoru","pl-PL":"Yoru","pt-BR":"Yoru","th-TH":"Yoru","ru-RU":"Yoru","tr-TR":"YORU","vi-VN":"Yoru","zh-CN":"夜露","zh-TW":"夜戮"}'::jsonb, '{"es-MX":"El nativo de Japón, Yoru, abre agujeros a través de la realidad para infiltrarse en las líneas enemigas sin ser visto. Con engaños y agresividad por igual, sorprende a sus objetivos antes de que sepan dónde buscarlo.","it-IT":"Yoru arriva dal Giappone per aprire squarci nella realtà e infiltrarsi furtivamente dietro le linee nemiche. Usando un mix di aggressività e sotterfugi, riesce ad avere la meglio su qualsiasi bersaglio prima ancora che si accorga della sua presenza.","ar-AE":"يُحدث يورو المتحدر من اليابان ثقوبًا في نسيج عالم الواقع ذاته ليتسلل وراء خطوط العدو متخفيًا. ومع اعتماده على ذات القدر من المكر والهجوم، يستطيع النيل من كل هدف قبل أن يدرك ما حلّ به.","es-ES":"Yoru, nacido en Japón, abre agujeros en el tejido de la realidad para infiltrarse tras las líneas enemigas sin ser visto. Utiliza el engaño y la agresividad por igual para acabar con sus objetivos antes de que sepan qué ha pasado.","en-US":"Japanese native Yoru rips holes straight through reality to infiltrate enemy lines unseen. Using deception and aggression in equal measure, he gets the drop on each target before they know where to look.","de-DE":"Der Japaner Yoru reißt Löcher in die Realität, um unbeobachtet hinter die feindlichen Linien zu gelangen. Er setzt gleichermaßen auf Irreführung und Aggression und ist seinen Gegnern bereits einen Schritt voraus, bevor sie wissen, wie ihnen geschieht.","ja-JP":"日本出身のヨルは、次元の狭間を渡る能力で敵陣の真っ只中に潜入できる。策略と攻撃性を合わせ持つ彼に狙われた標的は、その姿を認識する前に最期の瞬間を迎えることになる。","ko-KR":"일본 출신의 요루는 현실에 구멍을 내어 적 진영으로 은밀히 침투합니다. 그는 공격성과 속임수를 활용해 적이 알아채기도 전에 임무를 완수합니다.","fr-FR":"Le Japonais Yoru perce des trous dans la réalité pour s''infiltrer derrière les lignes ennemies sans se faire repérer. En faisant preuve d''autant de ruse que d''agressivité, il prend ses cibles par surprise avant qu''elles n''aient le temps de se retourner.","id-ID":"Agen asal Jepang, Yoru, melubangi realitas untuk menyusup ke wilayah musuh tanpa terlihat. Dengan bermodal tipuan dan agresi yang seimbang, dia menghabisi tiap target sebelum mereka sadar ke mana harus melihat.","pl-PL":"Rodowity Japończyk Yoru wyrywa dziury w rzeczywistości, by niepostrzeżenie infiltrować linie wroga. Wykorzystując w równym stopniu podstęp i agresję, z zaskoczenia atakuje każdy kompletnie nieświadomy zagrożenia cel.","pt-BR":"Yoru, nativo do Japão, abre fendas na realidade para infiltrar as linhas inimigas sem ser visto. Ele usa tanto artimanhas quanto táticas agressivas, e os alvos são abatidos sem saber de onde o ataque veio.","th-TH":"Yoru หนุ่มญี่ปุ่นผู้สามารถแหวกมิติเพื่อเคลื่อนย้ายและแฝงตัวไปในกองทัพศัตรูได้อย่างแนบเนียน ด้วยเล่ห์เหลี่ยมและความดุดันที่มีมากพอกัน เขาสามารถกำจัดเป้าหมายได้ก่อนที่พวกมันจะทันตั้งตัวเสียอีก","ru-RU":"Уроженец Японии Yoru способен создавать разрывы в самой реальности, чтобы незаметно пробираться на вражескую территорию. Сила и хитрость позволяют ему заставать врагов врасплох – они даже не успеют понять, откуда пришла смерть.","tr-TR":"Japon Yoru, gerçeklikte açtığı geçitlerden geçerek düşman hattına sinsice sızıyor. Yanılsamalardan ve kaba kuvvetten eşit oranda faydalanarak hedeflerini göz açıp kapayıncaya kadar indiriyor.","vi-VN":"Đến từ Nhật Bản, Yoru có khả năng xé toang thực tại để xâm nhập vào hàng ngũ của địch mà không bị phát hiện. Với kỹ năng vừa đánh lừa vừa tấn công kẻ địch, con mồi của Yoru sẽ chẳng bao giờ biết được mình bị ai hạ gục.","zh-CN":"来自东亚的“夜露”能够直接撕裂现实空间，无声无息地渗透敌人的防线。他在战斗中喜欢虚实结合，在敌人尚未猜到他的位置时发动突然袭击。","zh-TW":"日本人夜戮可以撕裂現實世界的空間，潛入敵軍陣線而不被察覺。他同時運用欺敵和進攻策略先發制人，讓目標措手不及。"}'::jsonb, 'Stealth', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/displayicon.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/displayicon.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/killfeedportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/minimapportrait.png', null, 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/background.png', array['222b67ff', '0f1923ff', '261e4fff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, '{"es-MX":"Waylay","it-IT":"Waylay","ar-AE":"وايلاي","es-ES":"Waylay","en-US":"Waylay","de-DE":"Waylay","ja-JP":"ウェイレイ","ko-KR":"웨이레이","fr-FR":"Waylay","id-ID":"Waylay","pl-PL":"Waylay","pt-BR":"Waylay","th-TH":"Waylay","ru-RU":"Waylay","tr-TR":"WAYLAY","vi-VN":"Waylay","zh-CN":"幻棱","zh-TW":"維蕾"}'::jsonb, '{"es-MX":"La radiante prismática Waylay de Tailandia se transforma en luz mientras se lanza a toda velocidad por el campo de batalla, abatiendo a sus objetivos con fragmentos de luz antes de volver a ponerse a salvo, todo en un abrir y cerrar de ojos.","it-IT":"Originaria della Thailandia, la radiante prismatica Waylay si trasforma in luce mentre sfreccia per il campo di battaglia, abbattendo i suoi bersagli con frammenti luminosi prima di tornare al sicuro in un batter d''occhio.","ar-AE":"تتحول وايلاي التايلاندية المشعة الموشورية إلى ضوء حقيقي مع انطلاقها كالسهم عبر ساحة المعركة لتضرب أهدافها عبر شظايا الضوء قبل أن تعود إلى بر الأمان، وكل ذلك بلمح البصر.","es-ES":"La tailandesa Waylay es una prismática radiante capaz de transformarse en luz para desplazarse por el campo de batalla y eliminar a sus objetivos con fragmentos lumínicos antes de regresar a un lugar seguro en menos de lo que canta un gallo.","en-US":"Thailand''s prismatic radiant Waylay transforms into light itself as she darts across the battlefield, striking down her targets through shards of light before flitting back to safety, all in the blink of an eye.","de-DE":"Die prismatisch strahlende Waylay aus Thailand verwandelt sich in Licht, wenn sie über das Schlachtfeld flitzt und ihre Ziele mit Lichtsplittern niederschlägt, bevor sie sich blitzschnell in Sicherheit bringt.","ja-JP":"プリズムの力を使いこなすタイ出身のウェイレイは、光そのものへと姿を変えて戦場を駆け抜け、光の欠片を貫き標的を倒す。そして一瞬のうちに安全な場所へと舞い戻るのだ。","ko-KR":"프리즘처럼 빛나는 태국 출신 웨이레이는 빛으로 변신해 전장을 누비며 빛의 파편으로 적을 공격한 후 눈 깜짝할 사이에 다시 안전한 곳으로 돌아갑니다.","fr-FR":"Waylay, la prismatique radiante de Thaïlande, se transforme en particules de lumière pour filer sur le champ de bataille. Elle frappe ses cibles à l''aide d''éclats de lumière avant de se remettre à l''abri, le tout en un clin d''œil.","id-ID":"Waylay, agen Thailand yang berpijar prismatik, berubah menjadi cahaya saat ia melesat melintasi medan tempur. Ia menyerang targetnya melalui secercah cahaya dan langsung mengamankan diri dalam sekejap mata.","pl-PL":"Pryzmatyczna promienista Waylay z Tajlandii przeistacza się w czyste światło i mknie przez pole bitwy, rażąc swoje cele odłamkami światła, a po wszystkim przemyka z powrotem w bezpieczne miejsce – wszystko to w mgnieniu oka.","pt-BR":"Waylay, a Radiante prismática da Tailândia, se transforma em pura luz e atravessa o campo de batalha abatendo os alvos com estilhaços luminosos antes de recuar. Tudo em um piscar de olhos.","th-TH":"Waylay ผู้เปล่งแสงสีรุ้งจากประเทศไทยจะกลายร่างเป็นแสงสว่างขณะพุ่งตัวไปทั่วสนามรบ และโจมตีเป้าหมายด้วยเศษเสี้ยวแห่งแสงก่อนจะกลับไปยังพื้นที่ปลอดภัยในชั่วพริบตา","ru-RU":"Сияющая Waylay из Таиланда превращается в сам свет, молниеносно перемещаясь по полю боя. Она поражает цели осколками света, а затем стремительно возвращается в безопасное место – и все это в мгновение ока.","tr-TR":"Taylandlı prizmatik radyant Waylay, bizzat ışığın kendisine dönüşüp savaş alanının bir ucundan diğer ucuna fırlar. Hedeflerini göz açıp kapayıncaya kadar ışık parçalarıyla alt eden Waylay daha onlar ne olduğunu anlamadan güvenli bir noktaya dönmüştür bile.","vi-VN":"Waylay - radiant với sức mạnh lăng kính tới từ Thái Lan - có khả năng biến thành ánh sáng để lao quanh chiến trường, tấn công mục tiêu bằng những mảnh vỡ ánh sáng trước khi bay trở lại nơi an toàn chỉ trong chớp mắt.","zh-CN":"来自暹罗湾北岸的“幻棱”是一名拥有棱晶能力的源能者，可以将自己变幻成光，在战场上穿梭自如，通过棱光碎片将敌人击倒后迅速撤退到安全区。眨眼之间，胜负已分。","zh-TW":"泰國的多彩光輝維蕾化身為光本身，在戰場上穿梭，透過光芒碎片擊倒目標後又迅速閃回安全之處，一切都發生在眨眼之間。"}'::jsonb, 'Terra', '2025-03-04T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/displayicon.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/displayicon.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/killfeedportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/minimapportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/background.png', array['482e61ff', '0f1923ff', '0f1923ff', '482e61ff'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, '{"es-MX":"Sage","it-IT":"Sage","ar-AE":"سايج","es-ES":"Sage","en-US":"Sage","de-DE":"Sage","ja-JP":"セージ","ko-KR":"세이지","fr-FR":"Sage","id-ID":"Sage","pl-PL":"Sage","pt-BR":"Sage","th-TH":"Sage","ru-RU":"Sage","tr-TR":"SAGE","vi-VN":"Sage","zh-CN":"贤者","zh-TW":"聖祈"}'::jsonb, '{"es-MX":"Sage, el bastión de China, proporciona seguridad para sí misma y para su equipo en cualquier lugar. Gracias a su capacidad de revivir a sus compañeros caídos y evitar ataques poderosos, proporciona un lugar de protección en medio del caótico campo de batalla.","it-IT":"Vero bastione della Cina, Sage genera sicurezza per se stessa e per i suoi alleati ovunque vada. È in grado di rianimare i compagni caduti e può prevenire gli assalti diretti, riuscendo così a fornire un porto sicuro anche sul campo di battaglia più infernale.","ar-AE":"توفر سايج، الحامية الصينية القوية، الأمان لنفسها ولأعضاء فريقها حيثما حلت. قدرتها على إنعاش الأصدقاء المسقطين وصد الهجمات العنيفة تجعل منها واحة من الأمان في قلب ميدان القتال المشتعل.","es-ES":"Originaria de China, Sage destaca a la hora de crear espacios seguros para su equipo allá donde va. Sus capacidades especiales para revivir a compañeros caídos en batalla y para mantener a raya los asaltos enemigos la convierten en la calma en mitad de la tormenta para su equipo.","en-US":"The bastion of China, Sage creates safety for herself and her team wherever she goes. Able to revive fallen friends and stave off forceful assaults, she provides a calm center to a hellish battlefield.","de-DE":"Die chinesische Wächterin Sage garantiert Sicherheit für sich und ihr Team, wohin auch immer sie geht. Dank ihrer einzigartigen Fähigkeit, gefallene Verbündete wiederzuerwecken und Angriffe abzuwehren, ist sie auf dem Schlachtfeld das Auge des Sturms.","ja-JP":"中国の守り手であるセージは、どこにいる時も仲間のために安全地帯を作り出すことができる。激しい攻撃を防ぎ、力尽きた戦友たちを蘇生する彼女は、過酷な戦場に一時の安らぎをもたらす存在なのだ。","ko-KR":"중국에서 온 세이지는 어디에서든 자신과 아군이 안전할 수 있도록 능력을 발휘합니다. 쓰러진 아군을 부활시키거나 강력한 공격을 피할 수 있는 능력으로 지옥 같은 전장에서 고요한 중심이 되어 줍니다.","fr-FR":"Véritable pilier originaire de Chine, Sage assure sa sécurité et celle de son équipe où qu''elle aille. Elle peut réanimer ses alliés tombés au combat et repousser les assauts ennemis pour offrir des oasis de tranquillité sur un champ de bataille infernal.","id-ID":"Layaknya benteng pertahanan dari Cina, Sage memberikan rasa aman bagi dirinya dan timnya di mana pun dia berada. Bisa membangkitkan sekutu yang gugur dan menahan serangan sengit, dia menjadi sumber ketenangan di tengah kacaunya battlefield.","pl-PL":"Sage to istna chińska twierdza, która sprawia, że zarówno ona, jak i jej drużyna mogą czuć się bezpiecznie w każdym miejscu. Potrafi wskrzeszać poległych towarzyszy i odpierać potężne ataki, co czyni z niej ostoję spokoju na piekielnym polu walki.","pt-BR":"Como uma verdadeira fortaleza chinesa, Sage traz segurança para si mesma e para a equipe aonde quer que vá. Capaz de reviver aliados e rechaçar investidas agressivas, ela oferece um centro de calmaria em meio ao caos da batalha.","th-TH":"Sage เปรียบเสมือนป้อมปราการของจีน เธอมอบความปลอดภัยแก่ตัวเองและเพื่อนร่วมทีมในทุกที่ที่เธอไปโดยอาศัยความสามารถในการชุบชีวิตเพื่อนร่วมทีมและการป้องกันการโจมตี เธอจึงเป็นศูนย์กลางของความสงบท่ามกลางสนามรบอันดุเดือด","ru-RU":"Защитница Китая Sage обеспечивает безопасность команды в бою. Благодаря возможности воскрешать союзников и сдерживать натиск врага она создает оазис покоя на жутком поле боя.","tr-TR":"Çinli ve kapı gibi Sage gittiği her yerde kendisini ve takımını güvende tutar. Öldürülen silah arkadaşlarını hayata döndürme yeteneği ve agresif saldırıları bertaraf edebilmesiyle, cehennemvari savaş meydanında etrafına huzur verir.","vi-VN":"Đến từ Trung Quốc, Sage luôn đảm bảo cho mình và đồng đội được an toàn ở bất cứ nơi đâu cô đến. Với khả năng hồi sinh đồng đội đã ngã xuống và đẩy lùi những cuộc tấn công dữ dội, cô là hậu phương vững chắc cho đồng đội trong những trận giao tranh khốc liệt.","zh-CN":"“贤者”是华夏文明的后代，她可以用超能力阻滞敌方攻势、为队友提供保护和治疗，甚至还能复活队友。有她在的地方，就如同是腥风血雨中的一处避风港。","zh-TW":"來自中國的聖祈，是宛如銅牆鐵壁一般的存在，無論身在何處，除了自保之外，也能確保隊伍的安全。她可以復活不支倒地的友軍，並擊退來犯的敵軍，可說在槍林彈雨的煉獄中，建造一座令人安心的庇護所。"}'::jsonb, 'Thorne', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/displayicon.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/displayicon.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/killfeedportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/minimapportrait.png', null, 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/background.png', array['1f5148ff', '0f1923ff', '102d23ff', '0f192300'], true, true, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, '{"es-MX":"Reyna","it-IT":"Reyna","ar-AE":"ريينا","es-ES":"Reyna","en-US":"Reyna","de-DE":"Reyna","ja-JP":"レイナ","ko-KR":"레이나","fr-FR":"Reyna","id-ID":"Reyna","pl-PL":"Reyna","pt-BR":"Reyna","th-TH":"Reyna","ru-RU":"Reyna","tr-TR":"REYNA","vi-VN":"Reyna","zh-CN":"芮娜","zh-TW":"蕾娜"}'::jsonb, '{"es-MX":"Desde el corazón de México, Reyna llega para dominar los duelos y aumentar su poder con cada asesinato. Su letalidad solo está limitada por tu destreza al usarla, por lo que su eficacia dependerá mucho de ello. ","it-IT":"Cresciuta nel cuore del Messico, Reyna domina i duelli uno contro uno, scatenandosi con ogni uccisione ottenuta. L''unico limite alle sue capacità è la sua abilità, che la rende fortemente dipendente dalle proprie prestazioni. ","ar-AE":"مع نشوئها في قلب المكسيك، تهيمن ريينا على القتال الفردي، حيث تتفجر قدراتها مع كل عملية قتل تحرزها. ولا يفوق قدراتها سوى مهارتها الفطرية، مما يجعلها مقاتلة تعتمد بشدة على الأداء. ","es-ES":"Desde el corazón de México, Reyna llega para dominar los combates uno contra uno, y cada asesinato que consigue la hace más fuerte. Su potencial es prácticamente infinito, y la destreza individual es el único factor determinante de su éxito. ","en-US":"Forged in the heart of Mexico, Reyna dominates single combat, popping off with each kill she scores. Her capability is only limited by her raw skill, making her sharply dependent on performance. ","de-DE":"Reyna wurde im Herzen Mexikos geschmiedet und dominiert den Einzelkampf, indem sie mit jedem Kill, den sie erzielt, auftrumpft. Allein ihr eigenes Können setzt ihren Fähigkeiten Grenzen, weshalb sie extrem abhängig von ihrer Leistung ist. ","ja-JP":"メキシコの中心部で鍛え上げられたレイナは一対一の状況で優位に立ち、敵を倒して命を食らう。その真の能力を開花できるかは、戦いのパフォーマンスによって大きく左右される。 ","ko-KR":"멕시코 중심부에서 태어난 레이나는 일대일 전투에 탁월하며 적을 처치할 때마다 강력해집니다. 그녀의 능력은 온전히 전투 실력에만 좌우됩니다.","fr-FR":"Originaire du cœur du Mexique, Reyna est une experte des combats singuliers qui se renforce à chaque élimination qu''elle réussit. Son efficacité n''est limitée que par son habileté, ce qui la rend très dépendante de ses propres performances. ","id-ID":"Ditempa di jantung Meksiko, Reyna mendominasi single combat dan menjadi makin kuat seiring tiap kill yang berhasil diraih. Kepiawaiannya hanya terhambat keahlian mentahnya, membuatnya sangat bergantung pada performa. ","pl-PL":"Zahartowana w sercu Meksyku Reyna dominuje w walkach jeden na jeden, rozkręcając się z każdym zdobytym zabójstwem. Ograniczają ją wyłącznie jej własne umiejętności – im lepiej sobie radzi, tym staje się potężniejsza. ","pt-BR":"Criada no coração do México, Reyna domina o combate individual e se destaca a cada abate efetuado. Sua capacidade só é limitada pela própria perícia, o que a torna bastante dependente de desempenho. ","th-TH":"หล่อหลอมขึ้นมาจากใจกลางเม็กซิโก Reyna เป็นที่หนึ่งในด้านการต่อสู้ตัวต่อตัว และยิ่งเก่งขึ้นทุกครั้งที่เก็บคิลได้ สิ่งเดียวที่เป็นขีดจำกัดความสามารถของเธอก็คือทักษะ ทำให้ประสิทธิภาพของเธอนั้นขึ้นอยู่กับฝีมือล้วน ๆ ","ru-RU":"Выросшая в самом сердце Мексики Reyna способна одолеть любого в бою один на один, и убийства придают ей сил. Ее мощь ограничена лишь мастерством и в значительной степени зависит от успехов в бою. ","tr-TR":"Meksika''nın kalbinden kopup gelen Reyna, teke tek çatışmalarda düşmanını ezer ve aldığı her skorla daha da coşar. Yapabilecekleri tamamen saf beceri gerektirir ve onu ciddi şekilde performansa dayalı kılar. ","vi-VN":"Được tôi luyện ngay giữa trái tim của Mexico, Reyna luôn áp đảo trong các giao tranh đơn lẻ và trở nên mạnh mẽ hơn với mỗi đối thủ bị cô hạ gục. Sức mạnh của cô chỉ bị giới hạn bởi kỹ năng cá nhân, cũng là điều khiến cô bị lệ thuộc khá nhiều vào phong độ thi đấu của người chơi. ","zh-CN":"“芮娜”的威名铸就于马德雷山脉。虽然初始技能有所限制，但她能在狭路相逢的决斗中变得越来越强，直至觉醒强大的超能力，这使得她的实战表现格外重要。 ","zh-TW":"在墨西哥中心經過歷練的蕾娜，單打獨鬥的能力超強，每擊殺一名敵軍，都可以獲得所向無敵的增益效果。她是否能主宰戰場，除了取決於技巧熟練度，也仰賴賽局上的表現。 "}'::jsonb, 'Vampire', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/displayicon.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/displayicon.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/killfeedportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/minimapportrait.png', null, 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/background.png', array['662d62ff', '0f1923ff', '2f2664ff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, '{"es-MX":"Omen","it-IT":"Omen","ar-AE":"أومن","es-ES":"Omen","en-US":"Omen","de-DE":"Omen","ja-JP":"オーメン","ko-KR":"오멘","fr-FR":"Omen","id-ID":"Omen","pl-PL":"Omen","pt-BR":"Omen","th-TH":"Omen","ru-RU":"Omen","tr-TR":"OMEN","vi-VN":"Omen","zh-CN":"幽影","zh-TW":"歐門"}'::jsonb, '{"es-MX":"Omen, el espectro de un recuerdo, caza entre las sombras. Ciega a los enemigos, se teletransporta a través del campo de batalla y los infunde de paranoia mientras intentan descubrir de dónde vendrá su próximo ataque.","it-IT":"Omen è uno spettro nato da un ricordo che caccia le sue prede nelle ombre. Acceca i nemici, si teletrasporta nel campo di battaglia e lascia che la paura si nutra dei suoi avversari, rosi dal dubbio di quale sarà la sua prossima vittima.","ar-AE":"يتربص شبح الذكريات أومن بفرائسه في جنح الظلام. حيث يعمي الأعداء ويتنقل بسرعة عبر الميدان لينشر الهلع بين أعدائه الذين يهرولون في الأنحاء محاولين اكتشاف مكان ضربته التالية.","es-ES":"Omen es un fantasma de tiempos pasados que acecha en las sombras. Es capaz de cegar al enemigo, teleportarse a través del campo de batalla y sembrar el caos y la paranoia mientras sus rivales se preguntan dónde atacará la próxima vez.","en-US":"A phantom of a memory, Omen hunts in the shadows. He renders enemies blind, teleports across the field, then lets paranoia take hold as his foe scrambles to uncover where he might strike next.","de-DE":"Omen ist das Phantom einer Erinnerung und jagt in den Schatten. Er kann Gegnern die Sicht nehmen und sich über die Karte teleportieren. Wenn die Gegner dann in Panik geraten und sein nächstes Ziel herausfinden wollen, schlägt er zu.","ja-JP":"記憶の幻影、オーメンは闇に潜んで敵を狩る。敵の視界を遮り、神出鬼没にテレポートすることで、次の一手を予測しようとする敵を徐々に疑心暗鬼へと誘うのだ。","ko-KR":"기억의 유령 오멘은 그림자 속에서 적들을 사냥합니다. 적들의 눈을 멀게 하고 전장 어느 곳이든 이동하며 피해망상을 일으키는 능력 때문에 상대는 다음 공격을 예측할 수 없어 혼란에 빠지게 됩니다.","fr-FR":"Spectre d''un souvenir, Omen chasse dans les ténèbres. Il aveugle les ennemis, se téléporte d''un bout à l''autre du champ de bataille et laisse la peur se répandre parmi ses adversaires qui se demandent qui sera sa prochaine victime.","id-ID":"Sesosok hantu dalam pikiran, Omen berburu dalam bayangan. Dia memberikan utilitas Blind pada musuh, berteleportasi melintasi battlefield, lalu membiarkan paranoia menghantui saat musuh berusaha menerka di mana dia akan menyerang berikutnya.","pl-PL":"Omen, upiór wspomnień, poluje pośród cieni. Oślepia wrogów, teleportuje się po polu walki i pozwala, by nieświadomych miejsca kolejnego ataku nieprzyjaciół ogarnęła paranoja.","pt-BR":"Omen, uma lembrança fantasmagórica, caça nas sombras. Ele cega os inimigos, teleporta-se pelo campo e deixa a paranoia assumir o controle enquanto o adversário tenta descobrir de onde virá seu próximo ataque.","th-TH":"Omen ออกล่าในเงามืด ดั่งปีศาจแห่งความทรงจำ เขาสามารถหายตัวข้ามสนาม ทำให้ศัตรูสูญเสียการมองเห็น แล้วปล่อยให้ความหวาดระแวงเข้าครอบงำศัตรู ก่อให้เกิดความกลัวว่าเมื่อไหร่ที่เขาจะลงมืออีกครั้ง","ru-RU":"Призрак из прошлого Omen наносит удары из тени. Он способен ослеплять врагов и незаметно перемещаться по полю боя, вселяя страх в сердца противников, тщетно пытающихся предугадать, откуда он нападет вновь.","tr-TR":"Bir anının hayaleti olan Omen gölgelerin içinde avlanır. Düşmanlarını kör eder, savaş alanını boydan boya kat eder ve paranoyanın, onun ne taraftan saldıracağını anlamaya çalışan rakiplerinin damarlarında gezinmesini sağlar.","vi-VN":"Tựa như bóng ma của ký ức, Omen săn lùng trong bóng tối. Khả năng khống chế tầm nhìn và dịch chuyển tức thời của hắn khiến mọi đối thủ phải hoang mang tột độ vì có thể bị tấn công bất cứ lúc nào từ bất cứ nơi đâu.","zh-CN":"“幽影”是暗影中的狩猎者，关于他的过去只有一段模糊的记忆。他能传送到战场的任意位置，还能剥夺敌人的视野与理智，使其陷入草木皆兵的境地。","zh-TW":"歐門是個記憶中的魅影，在暗影裡巡獵。他能蒙蔽敵人雙眼、在地圖上神出鬼沒，使詭譎的氣氛籠罩全域，而他的敵人永遠在心慌意亂之中，試圖猜測他接下來會在哪裡現身。"}'::jsonb, 'Wraith', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/displayicon.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/displayicon.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/killfeedportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/minimapportrait.png', null, 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/background.png', array['433178ff', '0f1923ff', '344673ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, '{"es-MX":"Jett","it-IT":"Jett","ar-AE":"جيت","es-ES":"Jett","en-US":"Jett","de-DE":"Jett","ja-JP":"ジェット","ko-KR":"제트","fr-FR":"Jett","id-ID":"Jett","pl-PL":"Jett","pt-BR":"Jett","th-TH":"Jett","ru-RU":"Jett","tr-TR":"JETT","vi-VN":"Jett","zh-CN":"捷风","zh-TW":"婕提"}'::jsonb, '{"es-MX":"Jett viene directamente de Corea del Sur. Su ágil y evasivo estilo de pelea le permite enfrentarse a riesgos que otros no pueden. Es imparable en todos los enfrentamientos y acaba con sus enemigos antes de que sepan qué los atacó.","it-IT":"Pronta a rappresentare la sua patria, la Corea del Sud, Jett ha uno stile di combattimento agile e sfuggente che le permette di affrontare rischi che nessun altro potrebbe correre. Aggira ogni scontro ed elimina i nemici prima ancora che possano rendersene conto.","ar-AE":"مع تمثيلها لبلدها الأصلي كوريا الجنوبية، تتمتع جيت بأسلوب قتالي رشيق شديد المراوغة يتيح لها القيام بمخاطرات لا يجرؤ أحد غيرها عليها. وهي تحقق السيطرة الكاملة في كل مناوشة وتسحق الأعداء حتى قبل أن يدركوا ما أصابهم.","es-ES":"Jett viene de Corea del Sur y su estilo de lucha ágil y evasivo le permite asumir grandes riesgos. En las refriegas, recorre el terreno en círculos y hace trizas a los enemigos con una rapidez espectacular.","en-US":"Representing her home country of South Korea, Jett''s agile and evasive fighting style lets her take risks no one else can. She runs circles around every skirmish, cutting enemies up before they even know what hit them.","de-DE":"Jett repräsentiert ihre Heimat Südkorea. Sie kämpft agil und weicht geschickt aus, weshalb sie Risiken eingehen kann wie niemand sonst. Sie umrundet Gefechte mit Leichtigkeit und schlitzt Gegner auf, bevor diese wissen, wie ihnen geschieht.","ja-JP":"韓国出身のジェットは、俊敏で捉え難い戦闘スタイルを持ち、他の誰にも真似できないような危険な行動を取ることができる。交戦地帯の周囲を走り回り、敵が何が起こったのか理解するよりも早く切り刻んでしまうのだ。","ko-KR":"한국 출신으로 신속하고 은밀하게 움직이는 제트는 다른 사람이라면 엄두도 못 낼 위험한 일도 마다하지 않습니다. 교전이 벌어질 때면 어김없이 상대보다 뛰어난 능력을 통해 기습적으로 공격합니다.","fr-FR":"Représentante de sa patrie, la Corée du Sud, Jett dispose d''un style de combat basé sur l''agilité et l''esquive, ce qui lui permet de prendre des risques qu''elle seule peut se permettre de prendre. Elle tourne autour des affrontements et découpe ses ennemis avant même qu''ils ne s''en rendent compte.","id-ID":"Mewakili negara asalnya, Korea Selatan, gaya bertarung Jett yang gesit dan banyak menghindar memungkinkannya mengambil risiko yang tidak bisa dilakukan orang lain. Dia berpindah secepat kilat saat bertarung, menebas musuh sebelum mereka menyadari apa yang terjadi.","pl-PL":"Zwinność i uniki Jett, reprezentującej Koreę Południową, pozwalają jej podejmować ryzyko, na jakie inni się nie decydują. Porusza się z niesamowitą szybkością, a jej wrogowie nie wiedzą, co ich trafiło.","pt-BR":"Representando a Coreia do Sul, sua terra natal, Jett tem um estilo de luta ágil e evasivo que permite que ela assuma riscos como ninguém. Ela corre em meio a qualquer confronto, cortando os inimigos antes mesmo que eles percebam quem ou o que os atingiu.","th-TH":"Jett คือตัวแทนจากเกาหลีใต้ บ้านเกิดของเธอ ด้วยรูปแบบการต่อสู้ที่คล่องตัวและสง่างาม ทำให้เธอเผชิญหน้ากับความเสี่ยงอย่างที่ไม่มีใครทำได้ เธอวิ่งไปรอบๆจุดปะทะ เชือดเฉือนศัตรูก่อนที่พวกเขาจะรู้ว่าถูกสิ่งใดโจมตี","ru-RU":"Представляющая Южную Корею Jett быстра и неуловима и может позволить себе рисковать чаще других. В любой стычке она заходит с флангов и быстро уничтожает растерявшегося противника.","tr-TR":"Anavatanı Güney Kore''yi temsil eden Jett''in çevik ve darbelerden kaçmaya dayalı dövüş tarzı, başkalarının alamadığı riskleri almasını sağlar. Her çatışmada üstünlüğünü belli eder ve rakipleri daha nerede olduğunu anlamadan onları kesip biçmeye başlar.","vi-VN":"Đến từ Hàn Quốc, với phong cách chiến đấu nhanh nhẹn và huyền ảo, Jett có thể thực hiện những pha tấn công liều lĩnh đến bất ngờ. Thoắt ẩn thoắt hiện trong các cuộc giao tranh, cô ra đòn chặn đứng đối thủ trước khi chúng kịp hiểu chuyện gì xảy ra.","zh-CN":"“捷风”是新罗人的后代，她灵活机动的战斗风格使她能够采取比常人更激进和冒险的策略。她可以在战场上肆意纵横，将敌人逐个击破，或是把他们打个措手不及。","zh-TW":"身為南韓代表，婕提身手矯捷，能使出他人所不能的精妙險招。交戰時她能把所有人耍得團團轉，以迅雷不及掩耳的速度秒殺敵人。"}'::jsonb, 'Wushu', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/displayicon.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/displayicon.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/killfeedportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/minimapportrait.png', null, 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/background.png', array['25607aff', '0f1923ff', '0f1923ff', '25607aff'], false, true, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
